"use client";

import React, { useEffect, useRef, useState } from 'react';
import { Send, Square, Zap, Paperclip, X, Plus, Image as ImageIcon, FileText, Globe } from 'lucide-react';
import { Language, Message, Theme } from '../types';
import { t } from '../utils/i18n';

interface ChatInputProps {
  input: string;
  setInput: (value: string) => void;
  inputImages?: string[]; // New: base64 images
  setInputImages?: (images: string[]) => void;
  onSend: () => void;
  onStop: () => void;
  isLoading: boolean;
  isDisabled: boolean;
  fontSize: number;
  language: Language;
  activeKeysCount: number;
  showTokenUsage?: boolean;
  history?: Message[];
  historyLimit?: number;
  onGetTokenCount?: (text: string) => Promise<number>;
  theme?: Theme;
  isSearchEnabled?: boolean;
  onToggleSearch?: (enabled: boolean) => void;
}

const ChatInput: React.FC<ChatInputProps> = ({
  input,
  setInput,
  inputImages = [],
  setInputImages,
  onSend,
  onStop,
  isLoading,
  isDisabled,
  fontSize,
  language,
  activeKeysCount,
  showTokenUsage = false,
  history = [],
  historyLimit = 0,
  onGetTokenCount,
  theme,
  isSearchEnabled,
  onToggleSearch
}) => {
  const textareaRef = useRef<HTMLTextAreaElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const textFileInputRef = useRef<HTMLInputElement>(null);
  const [tokenEstimate, setTokenEstimate] = useState(0);
  const [exactTokenCount, setExactTokenCount] = useState<number | null>(null);
  const [isToolsOpen, setIsToolsOpen] = useState(false);

  const isVSCodeTheme = theme === 'vscode-light' || theme === 'vscode-dark';
  const containerClass = isVSCodeTheme ? 'max-w-[85rem]' : 'max-w-5xl';

  // Determine dynamic min-height based on fontSize to prevent scrollbars for single lines
  const minHeight = Math.floor(fontSize * 1.5 + 36);
  const maxHeight = showTokenUsage ? 224 : 192;

  // Debounced API call for exact token count
  useEffect(() => {
    if (!showTokenUsage || !onGetTokenCount) return;
    setExactTokenCount(null);
    const timer = setTimeout(async () => {
        if (input.trim() || history.length > 0) {
            try {
                const count = await onGetTokenCount(input);
                if (count > -1) {
                    setExactTokenCount(count);
                }
            } catch (e) { }
        }
    }, 1000);
    return () => clearTimeout(timer);
  }, [input, history, showTokenUsage, onGetTokenCount]);

  // Estimate tokens (local fallback)
  useEffect(() => {
    if (!showTokenUsage) return;
    let textToCount = input;
    let historyContext = history;
    if (historyLimit > 0 && history.length > historyLimit) {
        historyContext = history.slice(-historyLimit);
    }
    const historyText = historyContext.map(m => m.text).join('');
    const totalChars = textToCount.length + historyText.length;
    const estimate = Math.ceil(totalChars / 4);
    setTokenEstimate(estimate);
  }, [input, history, showTokenUsage, historyLimit]);

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.nativeEvent.isComposing) return;
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      onSend();
    }
  };

  const handleInput = (e: React.FormEvent<HTMLTextAreaElement>) => {
    const target = e.target as HTMLTextAreaElement;
    target.style.height = 'auto';
    target.style.height = `${Math.min(target.scrollHeight, maxHeight)}px`;
  };

  useEffect(() => {
    if (textareaRef.current) {
      textareaRef.current.style.height = 'auto';
      const currentScrollHeight = textareaRef.current.scrollHeight;
      const targetHeight = Math.min(Math.max(currentScrollHeight, minHeight), maxHeight);
      textareaRef.current.style.height = `${targetHeight}px`;
    }
  }, [input, minHeight, maxHeight, fontSize]);

  const displayCount = exactTokenCount !== null ? exactTokenCount : tokenEstimate;

  // --- Image Handling ---

  const handleFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0 && setInputImages) {
      const files = Array.from(e.target.files) as File[];
      readAndAddImages(files);
      setIsToolsOpen(false); // Close menu after selection
    }
    if (fileInputRef.current) fileInputRef.current.value = ''; // Reset input
  };

  const handleTextFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
      const file = e.target.files[0];
      const reader = new FileReader();
      reader.onload = (ev) => {
        const content = ev.target?.result as string;
        const textToAppend = `\n\n\`\`\`${file.name}\n${content}\n\`\`\`\n`;
        // Use input prop directly since setInput type definition in props doesn't support functional update
        setInput((input + textToAppend).trimStart());
        setIsToolsOpen(false);
      };
      reader.readAsText(file);
    }
    if (textFileInputRef.current) textFileInputRef.current.value = '';
  };

  const handlePaste = (e: React.ClipboardEvent) => {
    if (!setInputImages) return;
    const items = e.clipboardData.items;
    const files: File[] = [];
    for (let i = 0; i < items.length; i++) {
        if (items[i].type.indexOf('image') !== -1) {
            const file = items[i].getAsFile();
            if (file) files.push(file);
        }
    }
    if (files.length > 0) {
        readAndAddImages(files);
    }
  };

  const readAndAddImages = (files: File[]) => {
      if (!setInputImages) return;
      const newImages: string[] = [];
      let processed = 0;

      files.forEach(file => {
          const reader = new FileReader();
          reader.onload = (e) => {
              if (e.target?.result && typeof e.target.result === 'string') {
                  newImages.push(e.target.result);
              }
              processed++;
              if (processed === files.length) {
                  setInputImages([...inputImages, ...newImages]);
              }
          };
          reader.readAsDataURL(file);
      });
  };

  const removeImage = (index: number) => {
      if (!setInputImages) return;
      const updated = [...inputImages];
      updated.splice(index, 1);
      setInputImages(updated);
  };

  return (
    <div className="p-3 md:p-4 pb-2 bg-transparent flex flex-col items-center">
      <div className={`${containerClass} w-full`}>

        {/* Collapsible Toolbar (Top Left) */}
        <div className="flex items-center gap-2 mb-2 px-1 h-8">
            <button
                onClick={() => setIsToolsOpen(!isToolsOpen)}
                className={`p-1.5 rounded-full transition-all duration-300 ${isToolsOpen ? 'bg-gray-200 dark:bg-gray-700 rotate-45' : 'bg-gray-100 dark:bg-gray-800 hover:bg-gray-200 dark:hover:bg-gray-700'} text-gray-500 dark:text-gray-400`}
                title={t('tooltip.expand_tools', language)}
            >
                <Plus className="w-5 h-5" />
            </button>

            <div className={`flex items-center gap-2 overflow-hidden transition-all duration-300 ease-in-out ${isToolsOpen ? 'w-auto opacity-100 translate-x-0' : 'w-0 opacity-0 -translate-x-4 pointer-events-none'}`}>
                 <button 
                    onClick={() => fileInputRef.current?.click()}
                    className="flex items-center gap-1.5 px-3 py-1.5 rounded-full bg-primary-50 dark:bg-primary-900/20 text-primary-600 dark:text-primary-400 hover:bg-primary-100 dark:hover:bg-primary-900/40 transition-colors text-xs font-medium whitespace-nowrap"
                    title={t('action.upload_image', language)}
                    disabled={isDisabled}
                 >
                    <ImageIcon className="w-4 h-4" />
                    <span>{t('action.upload_image', language)}</span>
                 </button>

                 <button 
                    onClick={() => textFileInputRef.current?.click()}
                    className="flex items-center gap-1.5 px-3 py-1.5 rounded-full bg-gray-100 dark:bg-gray-800 text-gray-600 dark:text-gray-300 hover:bg-gray-200 dark:hover:bg-gray-700 transition-colors text-xs font-medium whitespace-nowrap"
                    title={t('action.upload_file', language)}
                    disabled={isDisabled}
                 >
                    <FileText className="w-4 h-4" />
                    <span>{t('action.upload_file', language)}</span>
                 </button>

                 {onToggleSearch && (
                    <button
                        onClick={() => onToggleSearch(!isSearchEnabled)}
                        className={`flex items-center gap-1.5 px-3 py-1.5 rounded-full transition-colors text-xs font-medium whitespace-nowrap ${isSearchEnabled ? 'bg-blue-100 dark:bg-blue-900/40 text-blue-700 dark:text-blue-300' : 'bg-gray-100 dark:bg-gray-800 text-gray-600 dark:text-gray-300 hover:bg-gray-200 dark:hover:bg-gray-700'}`}
                        title={t('param.google_search', language)}
                        disabled={isDisabled}
                    >
                        <Globe className="w-4 h-4" />
                        <span>Search</span>
                    </button>
                 )}
            </div>

            <input 
                type="file" 
                ref={fileInputRef} 
                onChange={handleFileSelect} 
                accept="image/*" 
                multiple 
                className="hidden" 
            />
            <input 
                type="file" 
                ref={textFileInputRef} 
                onChange={handleTextFileSelect} 
                accept=".txt,.md,.js,.ts,.py,.json,.html,.css,.csv,.xml" 
                className="hidden" 
            />
        </div>

        {/* Image Preview Area */}
        {inputImages.length > 0 && (
            <div className="flex gap-2 mb-2 overflow-x-auto p-1 scrollbar-hide">
                {inputImages.map((img, idx) => (
                    <div key={idx} className="relative group shrink-0">
                        <img 
                            src={img} 
                            alt={`upload-${idx}`} 
                            className="h-16 w-16 object-cover rounded-lg border border-gray-200 dark:border-gray-700" 
                        />
                        <button 
                            onClick={() => removeImage(idx)}
                            className="absolute -top-1.5 -right-1.5 bg-gray-500 text-white rounded-full p-0.5 opacity-0 group-hover:opacity-100 transition-opacity hover:bg-red-500"
                        >
                            <X className="w-3 h-3" />
                        </button>
                    </div>
                ))}
            </div>
        )}

        <div className="relative flex items-center glass-panel rounded-2xl shadow-xl focus-within:ring-2 focus-within:ring-primary-500/50 focus-within:border-primary-500 transition-all">

          <textarea 
            ref={textareaRef}
            value={input} 
            onChange={(e) => setInput(e.target.value)} 
            onKeyDown={handleKeyDown}
            onInput={handleInput}
            onPaste={handlePaste}
            placeholder={activeKeysCount === 0 ? t('input.no_keys', language) : t('input.placeholder', language)} 
            disabled={isDisabled} 
            className={`w-full bg-transparent text-gray-900 dark:text-white p-3 md:p-4 pr-12 resize-none outline-none scrollbar-hide ${showTokenUsage ? 'pb-8 max-h-56' : 'max-h-48'}`}
            rows={1} 
            style={{ height: 'auto', minHeight: `${minHeight}px`, fontSize: `${fontSize}px`, lineHeight: '1.5' }} 
          />

          <div className="absolute right-2 bottom-2 flex flex-col items-end gap-1">
             <button 
              onClick={isLoading ? onStop : onSend} 
              disabled={(!input.trim() && inputImages.length === 0 && !isLoading) || isDisabled} 
              className={`p-2 rounded-xl flex items-center justify-center transition-all border-none ${isLoading ? 'bg-red-500 text-white hover:bg-red-600 shadow-md' : ((input.trim() || inputImages.length > 0) && !isDisabled ? 'bg-primary-600 text-white shadow-lg hover:bg-primary-500' : 'bg-gray-200 text-gray-400 dark:bg-gray-700 dark:text-gray-500 cursor-not-allowed')}`} 
              title={isLoading ? t('action.stop', language) : t('action.send', language)}
            >
              {isLoading ? <Square className="w-5 h-5 fill-current" /> : <Send className="w-5 h-5" />}
            </button>
          </div>

          {showTokenUsage && (
             <div className="absolute left-4 bottom-2 pointer-events-none select-none">
                <span 
                    className={`text-[11px] font-mono flex items-center gap-1 transition-colors ${exactTokenCount !== null ? 'text-primary-600 dark:text-primary-400 font-medium' : 'text-gray-400 dark:text-gray-500'}`}
                    title={exactTokenCount !== null ? t('label.exact_count', language) : t('label.estimated_count', language)}
                >
                   <Zap className="w-3 h-3" />
                   {exactTokenCount === null ? `~${displayCount.toLocaleString()}` : displayCount.toLocaleString()}
                </span>
             </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default ChatInput;

import { GoogleGenAI, GenerateContentResponse } from "@google/genai";
import { Message, Role, GenerationConfig, ModelInfo } from "../types";

export class GoogleService {
  /**
   * Lists available models from the Google Gemini API.
   */
  public async listModels(apiKey: string): Promise<ModelInfo[]> {
    try {
        const ai = new GoogleGenAI({ apiKey });
        const response = await ai.models.list();
        const models: ModelInfo[] = [];

        // @ts-ignore - The types for list() response iterator might vary slightly in some SDK versions
        for await (const model of response) {
            const m = model as any;
            if (m.name) {
                const name = m.name.replace('models/', '');
                models.push({
                    name: name,
                    displayName: m.displayName || name,
                    inputTokenLimit: m.inputTokenLimit,
                    outputTokenLimit: m.outputTokenLimit
                });
            }
        }
        // Filter for relevant models (Gemini, Flash, Pro, Thinking, Imagen)
        return models.filter(m => 
            m.name.includes('gemini') || m.name.includes('flash') || m.name.includes('pro') || m.name.includes('thinking') || m.name.includes('imagen')
        );
    } catch (e: any) {
        // Attach status if available in error message or object
        if (e.status === 403 || (e.message && e.message.includes("403"))) {
            const err = new Error("Permission Denied");
            (err as any).status = 403;
            throw err;
        }
        throw e;
    }
  }

  /**
   * Tests connection to Google Gemini API with a minimal generation request.
   */
  public async testConnection(apiKey: string, modelId: string = 'gemini-2.5-flash'): Promise<boolean> {
      try {
          const ai = new GoogleGenAI({ apiKey });
          // If checking Imagen model, use generateImages to test
          if (modelId.includes('imagen')) {
             await ai.models.generateImages({
                 model: modelId,
                 prompt: 'Test',
                 config: { numberOfImages: 1 }
             });
          } else {
             await ai.models.generateContent({
                 model: modelId,
                 contents: 'Test',
             });
          }
          // If we get here without error, the key is valid.
          return true;
      } catch (e) {
          return false;
      }
  }

  /**
   * Counts tokens for a chat history using Google Gemini API.
   */
  public async countTokens(
      apiKey: string,
      modelId: string,
      history: Message[],
      newMessage: string
  ): Promise<number> {
      try {
          const ai = new GoogleGenAI({ apiKey });

          // Filter out invalid messages (error or empty) to match generation logic
          // Note: Token counting might not fully support images yet in the SDK exactly same way, ignoring images for now for simplicity in count
          const validHistory = history.filter(msg => (msg.text && msg.text.trim().length > 0) && !msg.isError);

          const googleHistory = validHistory.map(msg => ({
              role: msg.role === Role.USER ? 'user' : 'model',
              parts: [{ text: msg.text }]
          }));

          const contents = [...googleHistory];

          if (newMessage && newMessage.trim().length > 0) {
              contents.push({
                  role: 'user',
                  parts: [{ text: newMessage }]
              });
          }

          const response = await ai.models.countTokens({
              model: modelId,
              contents: contents,
          });
          return response.totalTokens || 0;
      } catch (error) {
          return -1;
      }
  }

  /**
   * Generates images using Imagen models.
   */
  public async generateImage(apiKey: string, model: string, prompt: string): Promise<string> {
      try {
          const ai = new GoogleGenAI({ apiKey });
          const response = await ai.models.generateImages({
              model: model,
              prompt: prompt,
              config: {
                  numberOfImages: 1,
                  // outputMimeType: 'image/jpeg', // Optional
              }
          });

          // The SDK returns base64 image bytes
          // @ts-ignore - SDK typing might vary slightly
          const imageBytes = response.generatedImages?.[0]?.image?.imageBytes;

          if (imageBytes) {
              // Return as Markdown image
              return `![Generated Image](data:image/png;base64,${imageBytes})`;
          } else {
              throw new Error("No image generated.");
          }
      } catch (e: any) {
         if (e.message && e.message.includes('403')) (e as any).status = 403;
         throw e;
      }
  }

  /**
   * Streams chat response from Google Gemini API.
   * Returns text and optional grounding metadata.
   */
  public async streamChat(
      apiKey: string, 
      modelId: string, 
      history: Message[], 
      newMessage: string, 
      images: string[] | undefined,
      systemInstruction: string | undefined, 
      config: GenerationConfig,
      onChunk?: (text: string) => void,
      abortSignal?: AbortSignal
  ): Promise<{ text: string, groundingMetadata?: any }> {
      try {
        const ai = new GoogleGenAI({ apiKey });

        // Prepare history
        const googleHistory = history.map(msg => {
            const parts: any[] = [];

            // Add images from history if present
            if (msg.images && msg.images.length > 0) {
                 msg.images.forEach(img => {
                     // Convert data URI to inline data
                     // Format: data:image/png;base64,.....
                     const match = img.match(/^data:(.*?);base64,(.*)$/);
                     if (match) {
                         parts.push({
                             inlineData: {
                                 mimeType: match[1],
                                 data: match[2]
                             }
                         });
                     }
                 });
            }

            // Add text part
            if (msg.text) {
                parts.push({ text: msg.text });
            }

            return {
                role: msg.role === Role.USER ? 'user' : 'model',
                parts: parts
            };
        });

        const commonConfig: any = {
            systemInstruction: systemInstruction,
            temperature: config.temperature,
            topP: config.topP,
            topK: config.topK,
            maxOutputTokens: config.maxOutputTokens,
            frequencyPenalty: config.frequencyPenalty,
        };

        // Apply thinking budget if set and > 0
        if (config.thinkingBudget && config.thinkingBudget > 0) {
            commonConfig.thinkingConfig = { thinkingBudget: config.thinkingBudget };
        }

        // Apply Google Search Grounding if enabled
        if (config.googleSearch) {
            commonConfig.tools = [{ googleSearch: {} }];
        }

        const client = ai.chats.create({
            model: modelId,
            config: commonConfig,
            history: googleHistory
        });

        // Prepare new message contents
        const newParts: any[] = [];
        if (images && images.length > 0) {
            images.forEach(img => {
                const match = img.match(/^data:(.*?);base64,(.*)$/);
                if (match) {
                    newParts.push({
                        inlineData: {
                            mimeType: match[1],
                            data: match[2]
                        }
                    });
                }
            });
        }
        if (newMessage) {
            newParts.push({ text: newMessage });
        }

        if (config.stream) {
            // sendMessageStream accepts 'message' which can be string or Part[]
            const resultStream = await client.sendMessageStream({ message: newParts });
            let fullText = '';
            let stopReason = '';
            let groundingMetadata: any = null;

            for await (const chunk of resultStream) {
                if (abortSignal?.aborted) break;

                const response = chunk as GenerateContentResponse;
                const chunkText = response.text;

                // Capture Grounding Metadata
                if (response.candidates?.[0]?.groundingMetadata) {
                    groundingMetadata = response.candidates[0].groundingMetadata;
                }

                if (chunkText) {
                    fullText += chunkText;
                    if (onChunk) onChunk(fullText);
                } else {
                    // If text is undefined/empty, check candidates for finishReason
                    const candidate = response.candidates?.[0];
                    if (candidate?.finishReason) {
                        stopReason = candidate.finishReason;
                    }
                }
            }

            // If we have no text but a stop reason (e.g., SAFETY, RECITATION), display it
            if (!fullText && stopReason) {
                const reasonMessage = `[Response blocked. Reason: ${stopReason}]`;
                if (onChunk) onChunk(reasonMessage);
                const error = new Error(`Safety Block: ${stopReason}`);
                (error as any).status = 400; // Treat as bad request/block
                (error as any).isSafety = true;
                throw error;
            }

            return { text: fullText, groundingMetadata };
        } else {
            const result = await client.sendMessage({ message: newParts });
            // Handling non-streaming empty response
            if (!result.text && result.candidates?.[0]?.finishReason) {
                 const reason = result.candidates[0].finishReason;
                 const error = new Error(`Safety Block: ${reason}`);
                 (error as any).status = 400;
                 (error as any).isSafety = true;
                 throw error;
            }
            return { 
                text: result.text || '', 
                groundingMetadata: result.candidates?.[0]?.groundingMetadata 
            };
        }
      } catch (e: any) {
         // Enhance error object with status code if buried in message
         if (e.message) {
             if (e.message.includes('403')) (e as any).status = 403;
             if (e.message.includes('429')) (e as any).status = 429;
             if (e.message.includes('400')) (e as any).status = 400;
             if (e.message.includes('402')) (e as any).status = 402;
             if (e.message.includes('404')) (e as any).status = 404;
             if (e.message.includes('500')) (e as any).status = 500;
             if (e.message.includes('503')) (e as any).status = 503;
         }
         throw e;
      }
  }
}

import { Ollama } from 'ollama/browser';
import { Message, Role, GenerationConfig, ModelInfo } from "../types";
import { t } from "../utils/i18n";

/**
 * Service to handle Ollama API interactions.
 * Uses the official library for management, but raw fetch for reliable streaming in browser.
 */
export class OllamaService {

  /**
   * Creates a new Ollama client instance.
   * Forces usage of the local proxy path (/ollama-proxy) derived from window.location.origin.
   */
  private getClient(apiKey?: string): Ollama {
    // Automatically determine host based on current origin to ensure correct proxying
    // This handles both http (localhost) and https (production) correctly via the proxy
    const currentOrigin = window.location.origin;
    const host = `${currentOrigin}/ollama-proxy`;

    const config: { host: string; headers?: Record<string, string> } = {
      host: host
    };

    // If API Key is provided (e.g. for Ollama Cloud), add it as a Bearer token.
    if (apiKey && apiKey.trim()) {
      config.headers = { Authorization: 'Bearer ' + apiKey.trim() };
    }

    return new Ollama(config);
  }

  /**
   * Tests the connection by attempting to list models.
   * Note: baseUrl argument is preserved for interface compatibility but ignored.
   */
  public async testConnection(baseUrl: string, apiKey?: string): Promise<boolean> {
    try {
      const client = this.getClient(apiKey);
      await client.list();
      return true;
    } catch (e) {
      console.warn("Ollama connection test failed:", e);
      return false;
    }
  }

  /**
   * Fetches available models from the Ollama endpoint.
   * Note: baseUrl argument is preserved for interface compatibility but ignored.
   */
  public async listModels(baseUrl: string, apiKey?: string): Promise<ModelInfo[]> {
    try {
      const client = this.getClient(apiKey);
      const response = await client.list();

      // Map Ollama models to App's ModelInfo structure
      return response.models.map((m: any) => ({
          name: m.name,
          displayName: m.name,
          // Ollama list API doesn't explicitly return context limits, default to reasonable values
          inputTokenLimit: 4096, 
          outputTokenLimit: 4096
      })).sort((a: ModelInfo, b: ModelInfo) => a.name.localeCompare(b.name));
    } catch (error: any) {
      console.error("Ollama list models failed:", error);

      // Map status_code to status for consistent error handling in LLMService
      if (error.status_code) {
          (error as any).status = error.status_code;
      }

      if (error instanceof TypeError && error.message.includes('Failed to fetch')) {
          // Provide a more specific hint if it looks like a Mixed Content or CORS issue
          const netErr = new Error("Connection failed. Please check if the Ollama Cloud endpoint is reachable.");
          (netErr as any).status = 0; // Network error
          throw netErr;
      }
      throw error;
    }
  }

  /**
   * Helper to strip base64 header for Ollama (it expects raw base64 usually)
   */
  private extractBase64(dataUri: string): string {
      return dataUri.replace(/^data:image\/[a-z]+;base64,/, "");
  }

  /**
   * Streams chat completion from Ollama API.
   * Uses raw fetch with ReadableStream for better compatibility with browser streaming than the library.
   */
  public async streamChat(
    baseUrl: string, // Ignored
    modelId: string,
    history: Message[],
    newMessage: string,
    images: string[] | undefined,
    systemInstruction: string | undefined,
    config: GenerationConfig,
    apiKey?: string,
    onChunk?: (text: string) => void,
    abortSignal?: AbortSignal
  ): Promise<{ text: string, groundingMetadata?: any }> {
    // Determine proxy URL
    const currentOrigin = window.location.origin;
    const proxyUrl = `${currentOrigin}/ollama-proxy`;

    // Map App's history to Ollama's expected message format
    const messages = history.map(msg => ({
      role: msg.role === Role.USER ? 'user' : 'assistant',
      content: msg.text,
      // Pass images if present (strip prefix)
      images: msg.images ? msg.images.map(this.extractBase64) : undefined
    }));

    // Prepend system instruction if present
    if (systemInstruction) {
      messages.unshift({ role: 'system', content: systemInstruction, images: undefined });
    }

    // Append the new user message
    messages.push({ 
        role: 'user', 
        content: newMessage,
        images: images ? images.map(this.extractBase64) : undefined
    });

    const requestOptions = {
      model: modelId,
      messages: messages,
      stream: config.stream,
      options: {
          temperature: config.temperature,
          top_p: config.topP,
          top_k: config.topK,
          num_predict: config.maxOutputTokens,
          frequency_penalty: config.frequencyPenalty,
      }
    };

    try {
      if (config.stream) {
        const headers: Record<string, string> = {
            'Content-Type': 'application/json'
        };
        if (apiKey && apiKey.trim()) {
            headers['Authorization'] = `Bearer ${apiKey.trim()}`;
        }

        const response = await fetch(`${proxyUrl}/api/chat`, {
            method: 'POST',
            headers,
            body: JSON.stringify(requestOptions),
            signal: abortSignal
        });

        if (!response.ok) {
            const errorText = await response.text();
            let errorMessage = response.statusText;
            try {
                const json = JSON.parse(errorText);
                if (json.error) errorMessage = json.error;
            } catch { /* ignore */ }
            const error = new Error(`Ollama API Error: ${response.status} - ${errorMessage}`);
            (error as any).status = response.status;
            throw error;
        }

        if (!response.body) throw new Error("No response body");

        const reader = response.body.getReader();
        const decoder = new TextDecoder();
        let fullText = "";
        let buffer = "";

        while (true) {
            const { done, value } = await reader.read();
            if (done) break;

            const chunk = decoder.decode(value, { stream: true });
            buffer += chunk;

            const lines = buffer.split('\n');
            // Keep the last partial line in the buffer
            buffer = lines.pop() || "";

            for (const line of lines) {
                if (!line.trim()) continue;
                try {
                    const json = JSON.parse(line);
                    if (json.done) break;

                    if (json.message?.content) {
                        const content = json.message.content;
                        fullText += content;
                        if (onChunk) onChunk(fullText);
                    }
                } catch (e) {
                    console.warn("Error parsing Ollama stream chunk:", e);
                }
            }
        }

        return { text: fullText };

      } else {
        // Non-streaming mode: Use the library for simplicity
        const client = this.getClient(apiKey);
        const response = await client.chat({
          model: modelId,
          messages: messages,
          stream: false,
          options: requestOptions.options
        });

        if (abortSignal?.aborted) {
           throw new Error("Aborted by user");
        }

        return { text: response.message.content };
      }

    } catch (error: any) {
      if (error.name === 'AbortError' || abortSignal?.aborted) {
         throw new Error("Aborted by user");
      }

      // Map status_code to status for consistent error handling in LLMService
      if (error.status_code) {
          (error as any).status = error.status_code;
      }

      // Handle connection refused or other network errors generically
      if (error instanceof TypeError || error.message?.includes('Failed to fetch')) {
         const netErr = new Error("Network Error: Failed to fetch. Check connection.");
         (netErr as any).status = 0;
         throw netErr;
      }
      throw error;
    }
  }
}

import { Message, Role, GenerationConfig, ModelInfo } from "../types";
import { t } from "../utils/i18n"; // Import t for translations

/**
 * Service to handle OpenAI-compatible API interactions.
 */
export class OpenAIService {

  /**
   * Tests the connection by attempting to list models or perform a minimal check.
   */
  public async testConnection(apiKey: string, baseUrl: string): Promise<boolean> {
    try {
      const models = await this.listModels(apiKey, baseUrl);
      return Array.isArray(models) && models.length >= 0;
    } catch (e) {
      return false;
    }
  }

  /**
   * Tests if the key can perform a chat completion.
   */
  public async testChat(apiKey: string, baseUrl: string, modelId: string): Promise<boolean> {
    const cleanUrl = baseUrl.replace(/\/$/, '');
    try {
      const response = await fetch(`${cleanUrl}/chat/completions`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${apiKey}`
        },
        body: JSON.stringify({
          model: modelId,
          messages: [{ role: 'user', content: 'Hi' }],
          max_tokens: 1
        })
      });
      return response.ok;
    } catch (e) {
      return false;
    }
  }

  /**
   * Fetches available models from the OpenAI-compatible endpoint.
   */
  public async listModels(apiKey: string, baseUrl: string): Promise<ModelInfo[]> {
    const cleanUrl = baseUrl.replace(/\/$/, '');
    try {
      const response = await fetch(`${cleanUrl}/models`, {
        headers: {
          'Authorization': `Bearer ${apiKey}`
        }
      });

      if (!response.ok) {
        let errorMsg = response.statusText;
        try {
            const text = await response.text();
            if (text) {
                try {
                    const errorBody = JSON.parse(text);
                    if (errorBody.error?.message) errorMsg = errorBody.error.message;
                } catch {
                    errorMsg = text;
                }
            }
        } catch {
            // fallback
        }

        const error = new Error(`OpenAI API Error: ${response.status} - ${errorMsg}`);
        (error as any).status = response.status; 
        throw error;
      }

      const text = await response.text();
      if (!text) return [];

      const data = JSON.parse(text);
      if (data.data && Array.isArray(data.data)) {
        return data.data.map((m: any) => ({
            name: m.id,
            displayName: m.id,
            // OpenAI doesn't standardly expose limits in list models
            inputTokenLimit: 128000, 
            outputTokenLimit: 4096
        })).sort((a: ModelInfo, b: ModelInfo) => a.name.localeCompare(b.name));
      }
      return [];
    } catch (error: any) {
      if (error instanceof TypeError && error.message.includes('Failed to fetch')) { 
          const netErr = new Error("Network Error"); 
          (netErr as any).status = 0;
          throw netErr;
      }
      throw error; 
    }
  }

  /**
   * Streams chat completion from an OpenAI-compatible API.
   */
  public async streamChat(
    apiKey: string,
    baseUrl: string,
    modelId: string,
    history: Message[],
    newMessage: string,
    images: string[] | undefined,
    systemInstruction: string | undefined,
    config: GenerationConfig,
    onChunk?: (text: string) => void,
    abortSignal?: AbortSignal
  ): Promise<{ text: string, groundingMetadata?: any }> {
    const cleanUrl = baseUrl.replace(/\/$/, '');

    // Construct history with images support
    const openAIHistory = history.map(msg => {
      let content: any = msg.text;

      // Check if message has images
      if (msg.images && msg.images.length > 0) {
         content = [];
         if (msg.text) {
             content.push({ type: "text", text: msg.text });
         }
         msg.images.forEach(img => {
             content.push({
                 type: "image_url",
                 image_url: { url: img }
             });
         });
      }

      return {
        role: msg.role === Role.USER ? 'user' : 'assistant',
        content: content
      };
    });

    // Prepend system instruction
    if (systemInstruction) {
      openAIHistory.unshift({ role: 'system' as any, content: systemInstruction });
    }

    // Append current user message
    let newContent: any = newMessage;
    if (images && images.length > 0) {
        newContent = [];
        if (newMessage) {
            newContent.push({ type: "text", text: newMessage });
        }
        images.forEach(img => {
            newContent.push({
                type: "image_url",
                image_url: { url: img }
            });
        });
    }

    openAIHistory.push({ role: 'user', content: newContent });

    const requestBody = {
      model: modelId,
      messages: openAIHistory,
      temperature: config.temperature,
      top_p: config.topP,
      max_tokens: config.maxOutputTokens,
      stream: config.stream,
      frequency_penalty: config.frequencyPenalty,
    };

    try {
        const response = await fetch(`${cleanUrl}/chat/completions`, {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json',
                'Authorization': `Bearer ${apiKey}`
            },
            body: JSON.stringify(requestBody),
            signal: abortSignal
        });

        if (!response.ok) {
            let errorMsg = response.statusText;
            try {
                const text = await response.text();
                if (text) {
                    try {
                        const errorBody = JSON.parse(text);
                        if (errorBody.error?.message) errorMsg = errorBody.error.message;
                    } catch {
                        errorMsg = text;
                    }
                }
            } catch {
                // fallback
            }

            const error = new Error(errorMsg);
            (error as any).status = response.status; 
            throw error;
        }

        if (config.stream) {
          const reader = response.body?.getReader();
          const decoder = new TextDecoder("utf-8");
          let fullText = "";
          let buffer = ""; // Buffer for partial SSE lines

          if (reader) {
            while (true) {
              const { done, value } = await reader.read();
              if (done) break;
              if (abortSignal?.aborted) {
                reader.cancel();
                break;
              }

              const chunk = decoder.decode(value, { stream: true });
              buffer += chunk;

              const lines = buffer.split("\n");
              // Keep the last partial line in the buffer
              buffer = lines.pop() || "";

              for (const line of lines) {
                const trimmedLine = line.trim();
                if (!trimmedLine || !trimmedLine.startsWith("data: ")) continue;

                const dataStr = trimmedLine.replace("data: ", "").trim();
                if (dataStr === "[DONE]") break;

                try {
                  const json = JSON.parse(dataStr);
                  const content = json.choices?.[0]?.delta?.content || "";
                  if (content) {
                    fullText += content;
                    if (onChunk) onChunk(fullText);
                  }
                } catch (e) {
                  // If JSON is incomplete, wait for next chunk
                  // In some implementations, buffer might need to be restored
                }
              }
            }
          }
          return { text: fullText };
        } else {
          const text = await response.text();
          if (!text) return { text: "" };
          const data = JSON.parse(text);
          return { text: data.choices?.[0]?.message?.content || "" };
        }
    } catch (error: any) {
        if (error instanceof TypeError && error.message.includes('Failed to fetch')) {
            const netErr = new Error("Network Error"); 
            (netErr as any).status = 0;
            throw netErr;
        }
        throw error; 
    }
  }
}

import { Message, KeyConfig, GenerationConfig, ModelProvider, ModelInfo, Language, KeyGroup } from "../types";
import { OpenAIService } from "./openaiService";
import { GoogleService } from "./googleService";
import { OllamaService } from "./ollamaService";
import { t } from "../utils/i18n";

/**
 * 队列任务接口定义
 */
interface RequestTask {
  execute: () => Promise<any>;
  resolve: (value: any) => void;
  reject: (reason?: any) => void;
  abortSignal?: AbortSignal;
}

interface LLMServiceCallbacks {
    onKeyError?: (id: string, errorCode?: string, isFatal?: boolean) => void;
    onStatusMessage?: (message: string, type: 'info' | 'warning' | 'error' | 'success') => void;
}

/**
 * LLM 核心服务类：处理多提供商交互。
 * 包含：API 密钥轮询、负载均衡、请求队列处理。
 */
export class LLMService {
  private keys: KeyConfig[] = [];
  private keyGroups: KeyGroup[] = [];
  private keyIndex: number = 0; // 当前轮询到的 Key 索引
  private keyUsageCount: number = 0; // 当前 Key 已使用的次数

  // 队列管理状态：确保 API 请求按顺序处理，避免高并发冲突
  private requestQueue: RequestTask[] = [];
  private isProcessingQueue: boolean = false;

  private openAIService: OpenAIService;
  private googleService: GoogleService;
  private ollamaService: OllamaService;

  private onKeyError?: (id: string, errorCode?: string, isFatal?: boolean) => void;
  private onStatusMessage?: (message: string, type: 'info' | 'warning' | 'error' | 'success') => void;

  constructor(
      initialKeys: KeyConfig[], 
      callbacksOrOnError?: LLMServiceCallbacks | ((id: string, errorCode?: string, isFatal?: boolean) => void)
  ) {
    this.updateKeys(initialKeys);
    this.openAIService = new OpenAIService();
    this.googleService = new GoogleService();
    this.ollamaService = new OllamaService();

    if (typeof callbacksOrOnError === 'function') {
        this.onKeyError = callbacksOrOnError;
    } else if (callbacksOrOnError) {
        this.onKeyError = callbacksOrOnError.onKeyError;
        this.onStatusMessage = callbacksOrOnError.onStatusMessage;
    }
  }

  /**
   * 更新 API 密钥池
   */
  public updateKeys(newKeys: KeyConfig[], keyGroups: KeyGroup[] = []) {
    this.keys = newKeys;
    this.keyGroups = keyGroups;
    // 索引越界安全检查
    if (this.keyIndex >= this.keys.length) {
        this.keyIndex = 0;
        this.keyUsageCount = 0;
    }
  }

  private getGroupName(groupId?: string): string | undefined {
    if (!groupId) return undefined;
    return this.keyGroups.find(g => g.id === groupId)?.name;
  }

  /**
   * 将任务推入队列并触发处理逻辑
   */
  private async enqueueTask<T>(execute: () => Promise<T>, abortSignal?: AbortSignal): Promise<T> {
    return new Promise((resolve, reject) => {
      if (abortSignal?.aborted) {
        return reject(new Error("Aborted by user"));
      }

      this.requestQueue.push({
        execute,
        resolve,
        reject,
        abortSignal
      });

      this.processQueue();
    });
  }

  /**
   * 顺序处理队列中的任务 (FIFO)
   */
  private async processQueue() {
    if (this.isProcessingQueue || this.requestQueue.length === 0) return;

    this.isProcessingQueue = true;

    while (this.requestQueue.length > 0) {
      const task = this.requestQueue.shift();
      if (!task) continue;

      if (task.abortSignal?.aborted) {
        task.reject(new Error("Aborted by user"));
        continue;
      }

      try {
        const result = await task.execute();
        task.resolve(result);
      } catch (error) {
        task.reject(error);
      }
    }

    this.isProcessingQueue = false;
  }

  /**
   * 获取模型列表
   */
  public async listModels(keyConfig: KeyConfig): Promise<ModelInfo[]> {
    return this.enqueueTask(async () => {
      if (keyConfig.provider === 'openai') {
          if (!keyConfig.baseUrl) throw new Error("Base URL is required for OpenAI provider");
          return await this.openAIService.listModels(keyConfig.key, keyConfig.baseUrl);
      } else if (keyConfig.provider === 'ollama') {
          return await this.ollamaService.listModels(keyConfig.baseUrl || '', keyConfig.key);
      } else {
          return await this.googleService.listModels(keyConfig.key);
      }
    });
  }

  /**
   * 测试连接
   */
  public async testConnection(keyConfig: KeyConfig): Promise<boolean> {
    return this.enqueueTask(async () => {
      const modelToUse = keyConfig.model || (keyConfig.provider === 'openai' ? 'gpt-3.5-turbo' : 'gemini-2.5-flash');
      try {
          if (keyConfig.provider === 'openai') {
              if (!keyConfig.baseUrl) return false;
              return await this.openAIService.testChat(keyConfig.key, keyConfig.baseUrl, modelToUse);
          } else if (keyConfig.provider === 'ollama') {
              return await this.ollamaService.testConnection(keyConfig.baseUrl || '', keyConfig.key);
          } else {
              return await this.googleService.testConnection(keyConfig.key, modelToUse);
          }
      } catch (e) {
          return false;
      }
    });
  }

  /**
   * 核心算法：轮询策略
   * 寻找下一个可用的 API 密钥，考虑：活跃状态、速率限制冷却时间、单个 Key 的轮询配额。
   */
  private getNextAvailableKey(lang: Language): KeyConfig {
    const activeKeys = this.keys.filter(k => k.isActive);

    if (activeKeys.length === 0) {
      throw new Error(t('error.no_active_keys', lang));
    }

    const attempts = activeKeys.length;
    let selectedKey: KeyConfig | null = null;
    let selectedIndex = -1;

    for (let i = 0; i < attempts; i++) {
        const idx = (this.keyIndex + i) % activeKeys.length;
        const candidate = activeKeys[idx];

        // 检查冷却时间：如果被 429 限制，进入 1 分钟冷却期
        if (candidate.isRateLimited && Date.now() - candidate.lastUsed < 60000) {
            continue; 
        }

        // 检查轮询配额：如果当前 Key 还没用够设定的次数，继续用它
        if (i === 0 && this.keyUsageCount < (candidate.usageLimit || 1)) {
             selectedKey = candidate;
             selectedIndex = idx;
             break;
        }

        // 切换到下一个 Key
        if (i > 0) {
            selectedKey = candidate;
            selectedIndex = idx;
            break;
        }
    }

    // 如果所有 Key 都因为某种原因被跳过，强制选择当前索引的下一个
    if (!selectedKey) {
        selectedIndex = (this.keyIndex + 1) % activeKeys.length;
        selectedKey = activeKeys[selectedIndex];
    }

    // 如果发生了索引切换，重置单密钥使用计数
    if (this.keyIndex !== selectedIndex) {
        this.keyIndex = selectedIndex;
        this.keyUsageCount = 0;
    }

    this.keyUsageCount++;
    return selectedKey;
  }

  private getKeyDisplayIndex(id: string): number {
      return this.keys.findIndex(k => k.id === id) + 1;
  }

  /**
   * 错误分级处理逻辑
   * 将 API 返回的原始错误转化为用户可读的本地化语言。
   */
  private getErrorMessage(error: any, lang: Language): string {
      const status = error.status || error.statusCode;
      const msg = error.message?.toLowerCase() || '';

      if (status === 401 || msg.includes('401') || msg.includes('invalid api key')) return t('error.invalid_api_key', lang);
      if (status === 402 || msg.includes('402') || msg.includes('billing')) return t('error.billing_required', lang);
      if (status === 403 || msg.includes('403') || msg.includes('permission denied')) return t('error.permission_denied', lang);
      if (status === 404 || msg.includes('404') || msg.includes('not found')) return t('error.model_not_found', lang);
      if (status === 429 || msg.includes('429') || msg.includes('quota') || msg.includes('rate limit')) return t('error.quota_exceeded', lang);
      if (status === 400 || msg.includes('400')) {
          if (msg.includes('safety') || error.isSafety) return t('error.safety_block', lang);
          if (msg.includes('context')) return t('error.context_length_exceeded', lang);
          return t('error.bad_request', lang);
      }
      if (status === 500 || status === 502 || status === 503 || msg.includes('500')) return t('error.server_error', lang);
      if (status === 0 || msg.includes('network') || msg.includes('fetch')) return t('error.network_issue', lang);

      return error.message || t('error.unexpected_error', lang);
  }

  /**
   * 节点 5: 核心重试与分发逻辑
   * 在发生非致命错误（如速率限制）时自动切换密钥并重试。
   */
  public async streamChatResponse(
    _ignoredGlobalModelId: string, 
    history: Message[],
    newMessage: string,
    images: string[] | undefined,
    systemInstruction: string | undefined,
    generationConfig: GenerationConfig,
    onChunk?: (text: string) => void,
    abortSignal?: AbortSignal,
    lang: Language = 'en'
  ): Promise<{ text: string, usedKeyIndex: number, provider: ModelProvider, usedModel: string, groundingMetadata?: any }> {

    return this.enqueueTask(async () => {
        const activeKeysCount = this.keys.filter(k => k.isActive).length;
        // 最大重试次数为活跃密钥数的 2 倍
        const maxRetries = Math.max(activeKeysCount * 2, 2); 
        let attempts = 0;
        const validHistory = history.filter(msg => (msg.text && msg.text.trim().length > 0) || (msg.images && msg.images.length > 0));

        let lastError: any = null;
        let lastGroupId: string | undefined = undefined;

        while (attempts < maxRetries) {
            let keyConfig: KeyConfig;
            try {
                keyConfig = this.getNextAvailableKey(lang);
            } catch (e: any) {
                throw e;
            }

            const currentKeyIndex = this.getKeyDisplayIndex(keyConfig.id);
            const currentGroupId = keyConfig.groupId;
            const groupName = this.getGroupName(currentGroupId);

            // Notify on switch (Retry or Rotation)
            // Skip notification for the very first attempt unless debugging, to be less noisy? 
            // The prompt asks for "Every key switch", so we include retries.
            if (attempts > 0) {
                let msg = t('msg.switching_key', lang).replace('{index}', currentKeyIndex.toString());
                // Detect Group Switch specifically
                if (currentGroupId && lastGroupId && currentGroupId !== lastGroupId && groupName) {
                     msg += ` (${t('msg.switching_group', lang).replace('{group}', groupName)})`;
                }
                this.onStatusMessage?.(msg, 'info');
            }

            lastGroupId = currentGroupId;

            const modelToUse = keyConfig.model || _ignoredGlobalModelId || 'gemini-3-flash-preview';

            try {
                let response = { text: "", groundingMetadata: undefined };

                // 根据提供商分发请求
                if (keyConfig.provider === 'google' && modelToUse.toLowerCase().includes('imagen')) {
                     const imageMarkdown = await this.googleService.generateImage(keyConfig.key, modelToUse, newMessage);
                     response = { text: imageMarkdown, groundingMetadata: undefined };
                } 
                else if (keyConfig.provider === 'openai') {
                    if (!keyConfig.baseUrl) throw new Error(t('error.base_url_required', lang));
                    response = await this.openAIService.streamChat(
                        keyConfig.key, keyConfig.baseUrl, modelToUse, validHistory, 
                        newMessage, images, systemInstruction, generationConfig, onChunk, abortSignal
                    );
                } 
                else if (keyConfig.provider === 'ollama') {
                    response = await this.ollamaService.streamChat(
                        keyConfig.baseUrl || '', modelToUse, validHistory, 
                        newMessage, images, systemInstruction, generationConfig, keyConfig.key, onChunk, abortSignal
                    );
                } 
                else {
                    response = await this.googleService.streamChat(
                        keyConfig.key, modelToUse, validHistory, 
                        newMessage, images, systemInstruction, generationConfig, onChunk, abortSignal
                    );
                }

                return { 
                    text: response.text, 
                    usedKeyIndex: currentKeyIndex, 
                    provider: keyConfig.provider,
                    usedModel: modelToUse,
                    groundingMetadata: response.groundingMetadata
                };

            } catch (error: any) {
                if (abortSignal?.aborted) throw new Error("Aborted by user");

                lastError = error;
                let errorCode = 'Error';
                let statusCode = error.status || error.statusCode;

                if (!statusCode) {
                     const match = error.message?.match(/\b\d{3}\b/);
                     if (match) errorCode = match[0];
                     else if (error.message?.includes("Network")) errorCode = "Network";
                } else {
                    errorCode = statusCode.toString();
                }

                // Notify Error before switching
                const errorMessage = this.getErrorMessage(error, lang);
                this.onStatusMessage?.(
                    t('msg.key_error_verbose', lang)
                        .replace('{index}', currentKeyIndex.toString())
                        .replace('{error}', errorMessage), 
                    'error'
                );

                // 判断是否是致命错误：身份验证失败、计费问题、位置不支持等需要禁用密钥
                let isFatal = [401, 402, 403, 404].includes(statusCode);

                // 安全审核拦截不属于密钥问题，直接抛出给用户
                if (error.isSafety) {
                    throw new Error(this.getErrorMessage(error, lang));
                }

                if (this.onKeyError) {
                    this.onKeyError(keyConfig.id, errorCode, isFatal);
                }

                const localKey = this.keys.find(k => k.id === keyConfig.id);
                if (localKey) {
                    if (isFatal) localKey.isActive = false;
                    else {
                        // 速率限制错误：进入冷却
                        localKey.isRateLimited = true;
                        localKey.lastUsed = Date.now();
                        // 强制轮询配额用满，以便下次重试使用新 Key
                        this.keyUsageCount = 10000; 
                    }
                    localKey.lastErrorCode = errorCode;
                }

                if (this.keys.filter(k => k.isActive).length === 0) break; 

                attempts++;
                continue;
            }
        }

        if (lastError) throw new Error(this.getErrorMessage(lastError, lang));
        throw new Error(t('error.all_keys_failed', lang));
    }, abortSignal);
  }

  /**
   * Token 统计
   */
  public async countTokens(
      keyConfig: KeyConfig,
      history: Message[],
      newMessage: string,
      _ignoredSystemInstruction: string | undefined
  ): Promise<number> {
      return this.enqueueTask(async () => {
          if (keyConfig.provider !== 'google') return -1;
          return await this.googleService.countTokens(
              keyConfig.key, keyConfig.model || 'gemini-3-flash-preview', history, newMessage
          );
      });
  }
}

import React, { useMemo } from 'react';
import ReactMarkdown from 'react-markdown';
import remarkMath from 'remark-math';
import rehypeKatex from 'rehype-katex';
import remarkGfm from 'remark-gfm';
import { ExternalLink, AlertCircle, Globe } from 'lucide-react';
import { Role, Language, TextWrappingMode, Theme } from '../../types';
import { t } from '../../utils/i18n';
import { CodeBlock } from './CodeBlock';
import { ThoughtBlock } from './ThoughtBlock';

interface MessageContentProps {
  content: string;
  role: Role;
  isError?: boolean;
  images?: string[];
  textWrapping: TextWrappingMode;
  fontSize: number;
  language: Language;
  theme: Theme;
  onShowToast: (message: string, type: 'success' | 'error' | 'info') => void;
  onViewImage?: (url: string) => void;
  isLast?: boolean;
  groundingMetadata?: any; // New prop
}

const SearchSources: React.FC<{ metadata: any }> = ({ metadata }) => {
    if (!metadata || !metadata.groundingChunks || metadata.groundingChunks.length === 0) return null;

    const chunks = metadata.groundingChunks.filter((c: any) => c.web);
    if (chunks.length === 0) return null;

    return (
        <div className="mt-4 pt-3 border-t border-gray-100 dark:border-gray-700/50">
            <div className="flex items-center gap-2 mb-2 text-xs font-semibold text-gray-500 uppercase tracking-wide">
                <Globe className="w-3.5 h-3.5" />
                Sources
            </div>
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-2">
                {chunks.map((chunk: any, index: number) => (
                    <a 
                        key={index}
                        href={chunk.web.uri}
                        target="_blank"
                        rel="noopener noreferrer"
                        className="flex flex-col p-2 rounded-lg bg-gray-50 hover:bg-gray-100 dark:bg-gray-800/50 dark:hover:bg-gray-800 transition-colors border border-gray-100 dark:border-gray-700/50 group"
                    >
                        <span className="text-xs font-medium text-primary-600 dark:text-primary-400 truncate group-hover:underline">
                            {chunk.web.title || chunk.web.uri}
                        </span>
                        <span className="text-[10px] text-gray-400 truncate mt-0.5">
                            {new URL(chunk.web.uri).hostname}
                        </span>
                    </a>
                ))}
            </div>
        </div>
    );
};

export const MessageContent: React.FC<MessageContentProps> = React.memo(({
  content,
  role,
  isError,
  images,
  textWrapping,
  fontSize,
  language,
  theme,
  onShowToast,
  onViewImage,
  isLast = false,
  groundingMetadata
}) => {

  // Parse <think> blocks
  const { thoughts, cleanContent } = useMemo(() => {
    if (role !== Role.MODEL) {
        return { thoughts: [], cleanContent: content };
    }
    const thinkRegex = /<think>([\s\S]*?)(?:<\/think>|$)/g;
    const extractedThoughts: string[] = [];
    let match;
    // We clone the content to not mutate original during regex exec loops if needed, 
    // but regex.exec works on string reference.
    while ((match = thinkRegex.exec(content)) !== null) {
        let thoughtContent = match[1];

        // Anti-Flicker: Strip partial closing tags from the *end* of the thought content.
        // During streaming, the content might look like "...thoughts...</t" or "...thoughts...</thi"
        // This ensures the ThoughtBlock doesn't display broken tags while generating.
        if (isLast) {
             thoughtContent = thoughtContent.replace(/<\/t(?:h(?:i(?:n(?:k(?:>)? )?)?)?)?$/, '');
        }

        extractedThoughts.push(thoughtContent);
    }

    // Strip the thoughts
    let stripped = content.replace(/<think>[\s\S]*?(?:<\/think>|$)/g, '');

    // Fix for streaming: If the content ends with a partial <think> tag (e.g. "<", "<t", "<thin"),
    // strip it from the display text to avoid flickering raw tags.
    stripped = stripped.replace(/<(?:t(?:h(?:i(?:n(?:k)?)?)?)?)?$/, '');

    return { thoughts: extractedThoughts, cleanContent: stripped.trim() };
  }, [content, role, isLast]);

  const handleImageClick = (src: string) => {
      if (onViewImage) {
          onViewImage(src);
      } else {
          window.open(src, '_blank');
      }
  };

  const getWrappingClass = () => {
    switch (textWrapping) {
      case 'forced': return 'whitespace-pre-wrap break-all';
      case 'auto': return 'whitespace-normal break-words';
      case 'default': default: return 'whitespace-pre-wrap break-words';
    }
  };

  if (isError) {
    return <div className="flex items-center gap-2"><AlertCircle className="w-4 h-4" /><span>{content}</span></div>;
  }

  return (
    <div className={`markdown-body ${getWrappingClass()}`} style={{ fontSize: `${fontSize}px` }}>
        {thoughts.length > 0 && (
            <div className="mb-3 flex flex-col gap-2">
                {thoughts.map((thought, idx) => (
                    <ThoughtBlock 
                        key={idx} 
                        text={thought} 
                        lang={language} 
                        defaultOpen={isLast} // Auto-expand for the latest message (streaming)
                    />
                ))}
            </div>
        )}

        {/* Only render text content if it exists, logic handled by parent usually but safe to check */}
        {(cleanContent || (!images || images.length === 0)) && (
                <ReactMarkdown 
                remarkPlugins={[remarkGfm, remarkMath]} 
                rehypePlugins={[rehypeKatex]} 
                urlTransform={(value) => value}
                components={{ 
                    code({node, className, children, ...props}) { 
                        const match = /language-(\w+)/.exec(className || ''); 
                        const isInline = !match && !String(children).includes('\n'); 

                        if (isInline) {
                            return <code className={className} {...props}>{children}</code>;
                        }
                        return (
                            <CodeBlock 
                            language={match ? match[1] : 'text'} 
                            value={String(children).replace(/\n$/, '')} 
                            theme={theme}
                            onShowToast={onShowToast}
                            lang={language}
                            />
                        );
                    },
                    a({href, children}) {
                        return (
                            <a href={href} target="_blank" rel="noopener noreferrer">
                                {children}
                                <ExternalLink className="w-3 h-3 inline-block ml-0.5 opacity-70" />
                            </a>
                        );
                    },
                    img({src, alt}) {
                        return <img src={src} alt={alt} onClick={() => { if (typeof src === 'string') handleImageClick(src); }} style={{cursor: 'pointer'}} />;
                    },
                    input({checked, readOnly}) {
                        return <input type="checkbox" checked={checked} readOnly={readOnly} className="mr-2 accent-primary-600 rounded w-4 h-4 align-text-bottom cursor-default" />;
                    }
                }}
            >
                {cleanContent}
            </ReactMarkdown>
        )}

        {/* Google Search Grounding Sources */}
        <SearchSources metadata={groundingMetadata} />
    </div>
  );
});

import React, { useRef, useState, useEffect, useLayoutEffect, useMemo } from 'react';
import { User, X, Save, Edit2, RefreshCw, Trash2, Clock, Folder } from 'lucide-react';
import { Message, Role, Language, TextWrappingMode, Theme, AvatarVisibility } from '../types';
import { t } from '../utils/i18n';
import { KirbyIcon } from './Kirby';
import { AutoResizeTextarea } from './ui/AutoResizeTextarea';
import { MessageContent } from './message/MessageContent';

interface ChatMessageProps {
  msg: Message;
  isEditing: boolean;
  isConfirmingDelete: boolean;
  isLoading: boolean;
  bubbleTransparency: number;
  textWrapping: TextWrappingMode;
  fontSize: number;
  showModelName: boolean;
  showGroupName?: boolean;
  showResponseTimer?: boolean;
  language: Language;
  theme: Theme;
  kirbyThemeColor: boolean;
  onEditMessage: (id: string, newText: string) => void;
  onDeleteMessage: (id: string) => void;
  onRegenerate: (id: string) => void;
  setEditingId: (id: string | null) => void;
  setConfirmDeleteId: (id: string | null) => void;
  startEditing: (msg: Message) => void;
  deleteTimerRef: React.MutableRefObject<ReturnType<typeof setTimeout> | null>;
  onShowToast: (message: string, type: 'success' | 'error' | 'info') => void;
  smoothAnimation?: boolean;
  isLast?: boolean;
  onScrollToBottom?: () => void;
  avatarVisibility: AvatarVisibility;
  onViewImage?: (url: string) => void;
}

export const ChatMessage: React.FC<ChatMessageProps> = React.memo(({
  msg,
  isEditing,
  isConfirmingDelete,
  isLoading,
  bubbleTransparency,
  textWrapping,
  fontSize,
  showModelName,
  showGroupName,
  showResponseTimer = false,
  language,
  theme,
  kirbyThemeColor,
  onEditMessage,
  onDeleteMessage,
  onRegenerate,
  setEditingId,
  setConfirmDeleteId,
  startEditing,
  deleteTimerRef,
  onShowToast,
  smoothAnimation = true,
  isLast = false,
  onScrollToBottom,
  avatarVisibility,
  onViewImage
}) => {
  const safeText = msg.text || '';
  const [editText, setEditText] = useState(safeText);
  const [displayedText, setDisplayedText] = useState(safeText);
  const targetTextRef = useRef(safeText);
  const animationRef = useRef<number>(0);

  const isVSCodeTheme = theme === 'vscode-light' || theme === 'vscode-dark';
  const containerClass = isVSCodeTheme ? 'max-w-[85rem]' : 'max-w-5xl';

  // 检测消息是否为生成的图片（Markdown 图片且包含 Data URI）
  // 对于生成的图片跳过动画，避免 base64 源码闪烁
  const isGeneratedImage = useMemo(() => {
      const trimmed = safeText.trim();
      return msg.role === Role.MODEL && trimmed.startsWith('![') && trimmed.includes('(data:image/');
  }, [safeText, msg.role]);

  // --- 动画逻辑 ---
  useEffect(() => {
    targetTextRef.current = safeText;
    // 如果关闭动画、不是 AI 消息、错误消息、正在编辑或生成的图片，则直接显示完整文本
    if (!smoothAnimation || msg.role !== Role.MODEL || isEditing || isGeneratedImage) {
        setDisplayedText(safeText);
    }
  }, [safeText, msg.role, isEditing, smoothAnimation, isGeneratedImage]);

  useEffect(() => {
    if (isEditing) setEditText(safeText);
  }, [isEditing, safeText]);

  /**
   * 打字机动画循环
   * 根据缓冲区待处理字符数动态调整打字速度
   */
  useEffect(() => {
    if (!smoothAnimation || msg.role !== Role.MODEL || msg.isError || isEditing || isGeneratedImage) return;

    const animate = () => {
      setDisplayedText((current) => {
        const target = targetTextRef.current;
        if (current === target) return current;
        if (current.length > target.length) return target;

        const diff = target.length - current.length;

        /**
         * 动态调整打字步长：
         * 根据用户需求，提高比例为缓冲区字数 (diff) / 50。
         * 设置最小步长为 1，确保即使剩余字数较少也能匀速完成渲染。
         */
        const chunk = Math.max(1, Math.ceil(diff / 50));

        const nextLen = Math.min(target.length, current.length + chunk);
        const nextText = target.substring(0, nextLen);
        return nextText;
      });
      animationRef.current = requestAnimationFrame(animate);
    };

    animationRef.current = requestAnimationFrame(animate);
    return () => {
      if (animationRef.current) cancelAnimationFrame(animationRef.current);
    };
  }, [msg.role, msg.isError, isEditing, smoothAnimation, isGeneratedImage]);

  useLayoutEffect(() => {
      if (isLast && onScrollToBottom && smoothAnimation && msg.role === Role.MODEL && !isEditing && !isGeneratedImage) {
          onScrollToBottom();
      }
  }, [displayedText, isLast, onScrollToBottom, smoothAnimation, msg.role, isEditing, isGeneratedImage]);

  // --- 处理方法 ---

  const cancelEditing = () => { 
    setEditingId(null); 
    setEditText(''); 
    setConfirmDeleteId(null);
  };

  const saveEdit = () => { 
    if (editText.trim() !== safeText) onEditMessage(msg.id, editText); 
    setEditingId(null); 
    setConfirmDeleteId(null);
  };

  const handleKeyDown = (e: React.KeyboardEvent) => { 
    if (e.key === 'Enter' && !e.shiftKey) { 
      e.preventDefault(); 
      saveEdit(); 
    } 
    if (e.key === 'Escape') cancelEditing(); 
  };

  const handleDeleteClick = () => {
    setEditingId(null);
    if (isConfirmingDelete) {
      onDeleteMessage(msg.id);
      setConfirmDeleteId(null);
      if (deleteTimerRef.current) clearTimeout(deleteTimerRef.current);
    } else {
      setConfirmDeleteId(msg.id);
      if (deleteTimerRef.current) clearTimeout(deleteTimerRef.current);
      deleteTimerRef.current = setTimeout(() => {
        setConfirmDeleteId(null);
        deleteTimerRef.current = null;
      }, 3000);
    }
  };

  const handleRegenerateClick = () => {
    onRegenerate(msg.id);
    setConfirmDeleteId(null);
  }

  const handleImageClick = (src: string) => {
      if (onViewImage) {
          onViewImage(src);
      } else {
          window.open(src, '_blank');
      }
  };

  // --- 样式计算 ---

  const effectiveTransparency = isEditing ? 100 : bubbleTransparency;
  const borderAlpha = 0.5 + (effectiveTransparency / 100) * 0.5;
  const shadowAlpha = (100 - effectiveTransparency) / 100;

  const textShadowStyle = effectiveTransparency < 90 
    ? `0 1px 2px rgba(var(--color-theme-primary-rgb), ${shadowAlpha})` 
    : 'none';

  let backgroundColor;
  if (msg.role === Role.USER) {
       backgroundColor = `rgba(var(--color-theme-primary-rgb), ${effectiveTransparency / 100})`;
  } else if (msg.role === Role.MODEL && !msg.isError) {
       backgroundColor = `rgba(var(--color-theme-primary-rgb), ${(effectiveTransparency / 100) * 0.15})`;
  }

  const animationClass = smoothAnimation ? 'animate-pop-in' : '';
  const wrapperWidthClass = isEditing ? 'w-full max-w-full' : 'max-w-[95%] md:max-w-[85%]'; 
  const bubbleBorderColor = isVSCodeTheme ? 'transparent' : `rgba(var(--color-theme-primary-rgb), ${borderAlpha})`;

  const showAvatar = 
    avatarVisibility === 'always' || 
    (avatarVisibility === 'user-only' && msg.role === Role.USER) ||
    (avatarVisibility === 'model-only' && msg.role === Role.MODEL);

  return (
    <div className={`flex w-full ${containerClass} mx-auto ${msg.role === Role.USER ? 'justify-end' : 'justify-start'} animate-fade-in-up group`}>
        <div className={`flex gap-3 ${msg.role === Role.USER ? 'flex-row-reverse' : 'flex-row'} ${wrapperWidthClass}`}>

            {showAvatar && (
                <div className={`flex-shrink-0 w-8 h-8 rounded-full flex items-center justify-center mt-0.5 overflow-hidden ${msg.role === Role.USER ? 'bg-primary-600' : 'bg-transparent'} ${msg.isError ? 'bg-red-500' : ''}`}>
                    {msg.role === Role.USER ? <User className="w-5 h-5 text-white" /> : <div className="w-full h-full scale-150"><KirbyIcon theme={theme} isThemed={kirbyThemeColor} /></div>}
                </div>
            )}

            <div className={`flex flex-col min-w-0 ${msg.role === Role.USER ? 'items-end' : 'items-start'} w-full`}>
            <div 
                className={`relative px-3 py-2.5 rounded-2xl shadow-sm backdrop-blur-sm transition-all duration-300 w-full max-w-full origin-bottom-left ${animationClass} ${
                    msg.role === Role.USER 
                    ? 'text-white rounded-tr-sm border origin-bottom-right' 
                    : msg.isError 
                        ? 'bg-red-100 dark:bg-red-900/30 border border-red-200 dark:border-red-800 text-red-800 dark:text-red-200 rounded-tl-sm' 
                        : 'border text-gray-800 dark:text-gray-100 rounded-tl-sm'
                }`}
                style={
                    !msg.isError ? { 
                        backgroundColor,
                        borderColor: bubbleBorderColor,
                        textShadow: textShadowStyle
                    } : {}
                }
            >
                {/* 消息附件图片网格 */}
                {msg.images && msg.images.length > 0 && !isEditing && (
                    <div className="flex flex-wrap gap-2 mb-2">
                        {msg.images.map((img, idx) => (
                            <div key={idx} className="relative group">
                                <img 
                                    src={img} 
                                    alt="Message Attachment" 
                                    className="max-h-64 max-w-full rounded-lg cursor-pointer hover:opacity-90 transition-opacity" 
                                    onClick={() => handleImageClick(img)}
                                />
                            </div>
                        ))}
                    </div>
                )}

                {isEditing ? (
                <div className="w-full min-w-[200px]">
                    <AutoResizeTextarea 
                        value={editText} 
                        onChange={(e) => setEditText(e.target.value)} 
                        onKeyDown={handleKeyDown} 
                        fontSize={fontSize}
                        autoFocus
                        lang={language}
                    />
                    <div className="flex justify-end gap-2 mt-2">
                        <button 
                        onClick={cancelEditing} 
                        className={`p-2 rounded-lg transition-colors flex items-center justify-center ${
                            msg.role === Role.USER 
                                ? 'bg-white/20 text-white hover:bg-white/30' 
                                : 'bg-primary-600 text-white hover:bg-primary-700 shadow-sm'
                        }`} 
                        title={t('action.cancel', language)}
                        aria-label={t('action.cancel_edit', language)}
                    >
                            <X className="w-5 h-5 md:w-4 md:h-4"/>
                        </button>
                        <button 
                        onClick={saveEdit} 
                        className={`p-2 rounded-lg transition-colors flex items-center justify-center ${
                            msg.role === Role.USER 
                                ? 'bg-white/20 text-white hover:bg-white/30' 
                                : 'bg-primary-600 text-white hover:bg-primary-700 shadow-sm'
                        }`} 
                        title={t('action.confirm', language)}
                        aria-label={t('action.save_edit', language)}
                    >
                            <Save className="w-5 h-5 md:w-4 md:h-4"/>
                        </button>
                    </div>
                </div>
                ) : (
                    <MessageContent 
                        content={displayedText}
                        role={msg.role}
                        isError={msg.isError}
                        images={msg.images}
                        textWrapping={textWrapping}
                        fontSize={fontSize}
                        language={language}
                        theme={theme}
                        onShowToast={onShowToast}
                        onViewImage={onViewImage}
                        isLast={isLast} // Pass isLast to control auto-expansion of thoughts
                        groundingMetadata={msg.groundingMetadata}
                    />
                )}
            </div>

            <div className="flex flex-wrap items-center gap-x-2 gap-y-1 mt-1 px-1 min-h-[1.5rem]">
                <span className="text-[10px] text-gray-400 dark:text-gray-500 whitespace-nowrap">{new Date(msg.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</span>
                {msg.role === Role.MODEL && !msg.isError && (
                <div className="flex flex-wrap items-center gap-1">
                    {msg.keyIndex && (
                        <span className="text-[10px] font-mono bg-primary-50 dark:bg-primary-900/20 text-primary-600 dark:text-primary-400 px-1 rounded border border-primary-100 dark:border-primary-800 whitespace-nowrap" title={t('tooltip.key_index', language)}>#{msg.keyIndex}</span>
                    )}
                    {showGroupName && msg.groupName && (
                        <div className="flex items-center gap-0.5 text-[10px] font-mono bg-indigo-50 dark:bg-indigo-900/20 text-indigo-600 dark:text-indigo-400 px-1 rounded border border-indigo-100 dark:border-indigo-800 whitespace-nowrap" title={t('tooltip.group_name', language)}>
                            <Folder className="w-2.5 h-2.5" />
                            <span>{msg.groupName}</span>
                        </div>
                    )}
                    {showModelName && msg.model && (
                        <span className="text-[10px] font-mono bg-primary-50 dark:bg-primary-900/20 text-primary-600 dark:text-primary-400 px-1 rounded border border-primary-100 dark:border-primary-800 break-all max-w-[250px]" title={t('tooltip.model_used', language)}>{msg.model}</span>
                    )}
                    {showResponseTimer && msg.executionTime && (
                        <div className="flex items-center gap-0.5 text-[10px] font-mono bg-primary-50 dark:bg-primary-900/20 text-primary-600 dark:text-primary-400 px-1 rounded border border-primary-100 dark:border-primary-800 whitespace-nowrap" title={t('tooltip.response_time', language)}>
                            <Clock className="w-2.5 h-2.5" />
                            <span>{t('label.response_time', language).replace('{duration}', (msg.executionTime / 1000).toFixed(1))}</span>
                        </div>
                    )}
                </div>
                )}
                {!isLoading && !isEditing && (
                <div className={`flex items-center gap-2 opacity-0 group-hover:opacity-100 transition-opacity`}>
                    <button 
                    onClick={() => startEditing(msg)} 
                    className="p-4 md:p-1 text-gray-400 hover:text-primary-600 dark:hover:text-primary-400 transition-colors"
                    title={t('action.edit', language)}
                    aria-label={t('action.edit_message', language)}
                    >
                    <Edit2 className="w-3.5 h-3.5" />
                    </button>
                    <button 
                    onClick={handleRegenerateClick} 
                    className="p-4 md:p-1 text-gray-400 hover:text-primary-600 dark:hover:text-primary-400 transition-colors"
                    title={msg.role === Role.USER ? t('action.regenerate_from_user_message', language) : t('action.regenerate_response', language)}
                    aria-label={t('action.regenerate', language)}
                    >
                    <RefreshCw className="w-3.5 h-3.5" />
                    </button>
                    <button 
                    onClick={handleDeleteClick} 
                    className={`p-4 md:p-1 transition-colors ${isConfirmingDelete ? 'text-red-500 bg-red-50 dark:bg-red-900/20 rounded' : 'text-gray-400 hover:text-red-500'}`}
                    title={isConfirmingDelete ? t('action.confirm_delete', language) : t('action.delete', language)}
                    aria-label={t('action.delete_message', language)}
                    >
                    <Trash2 className="w-3.5 h-3.5" />
                    </button>
                </div>
                )}
            </div>
            </div>
        </div>
    </div>
  );
}, (prev, next) => {
  return (
    prev.msg === next.msg &&
    prev.isEditing === next.isEditing &&
    prev.isConfirmingDelete === next.isConfirmingDelete &&
    prev.isLoading === next.isLoading &&
    prev.bubbleTransparency === next.bubbleTransparency &&
    prev.textWrapping === next.textWrapping &&
    prev.fontSize === next.fontSize &&
    prev.showModelName === next.showModelName &&
    prev.showGroupName === next.showGroupName &&
    prev.showResponseTimer === next.showResponseTimer &&
    prev.language === next.language &&
    prev.theme === next.theme &&
    prev.kirbyThemeColor === next.kirbyThemeColor &&
    prev.smoothAnimation === next.smoothAnimation &&
    prev.isLast === next.isLast &&
    prev.avatarVisibility === next.avatarVisibility
  );
});

"use client";

import React, { useState, useEffect, useRef, Suspense, lazy } from 'react';
import { v4 as uuidv4 } from 'uuid';
import { LLMService } from './services/llmService';
import { Message, Role, GeminiModel, AppSettings, KeyConfig, ChatSession, ModelProvider, APP_VERSION, ToastMessage, DialogConfig, ModelInfo } from './types';
import ChatInterface from './components/ChatInterface';
import Sidebar from './components/Sidebar';
import { Header } from './components/Header';
import ChatInput from './components/ChatInput';
import { t } from './utils/i18n';
import { ToastContainer } from './components/ui/Toast';
import { CustomDialog } from './components/ui/CustomDialog';
import { executeFilterScript } from './utils/scriptExecutor';

const SettingsModal = lazy(() => import('./components/SettingsModal'));
const SecurityLock = lazy(() => import('./components/SecurityLock'));
const MobileMenu = lazy(() => import('./components/MobileMenu'));

const DEFAULT_MODEL = 'gemini-3-flash-preview';
const STORAGE_KEYS_KEY = 'gemini_omnichat_keys_v4';
const STORAGE_SETTINGS_KEY = 'gemini_omnichat_settings_v8'; 
const STORAGE_SESSIONS_KEY = 'gemini_omnichat_sessions_v1';
const STORAGE_ACTIVE_SESSION_KEY = 'gemini_omnichat_active_session_v1';
const STORAGE_KNOWN_MODELS_KEY = 'gemini_omnichat_known_models_v1';

const ENV_KEY = process.env.API_KEY || '';

const DEFAULT_KNOWN_MODELS: ModelInfo[] = [
    { name: 'gemini-3-flash-preview', inputTokenLimit: 1048576, outputTokenLimit: 8192 },
    { name: 'gemini-3-pro-preview', inputTokenLimit: 2097152, outputTokenLimit: 8192 }
];

const App: React.FC = () => {
  // --- 状态定义 ---
  const [sessions, setSessions] = useState<ChatSession[]>([]); // 会话列表
  const [activeSessionId, setActiveSessionId] = useState<string>(''); // 当前活动会话 ID
  const [messages, setMessages] = useState<Message[]>([]); // 当前会话的消息记录
  const [input, setInput] = useState(''); // 输入框文本
  const [inputImages, setInputImages] = useState<string[]>([]); // 待发送的图片
  const [isLoading, setIsLoading] = useState(false); // 是否正在生成回复
  const [isSummarizing, setIsSummarizing] = useState(false); // 是否正在总结标题
  const [isSettingsOpen, setIsSettingsOpen] = useState(false); // 设置弹窗开关
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false); // 移动端侧边栏开关
  const [isLocked, setIsLocked] = useState(false); // 隐私安全锁状态
  const [apiKeys, setApiKeys] = useState<KeyConfig[]>([]); // API 密钥池
  const [knownModels, setKnownModels] = useState<ModelInfo[]>(DEFAULT_KNOWN_MODELS); // 已知模型缓存

  // --- 应用配置 ---
  const [settings, setSettings] = useState<AppSettings>({
    defaultModel: DEFAULT_MODEL,
    defaultBaseUrl: 'https://api.openai.com/v1',
    systemPrompts: [],
    theme: 'light', 
    language: 'zh', 
    fontSize: 14,
    textWrapping: 'auto', 
    bubbleTransparency: 100, 
    showModelName: true, 
    showGroupName: false,
    kirbyThemeColor: false, 
    showTokenUsage: false, 
    showResponseTimer: false, 
    smoothAnimation: true, 
    avatarVisibility: 'always', 
    enableAutoMemory: false, // Default off
    autoMemoryInterval: 20, // Default interval
    historyContextLimit: 0, 
    security: {
        enabled: false,
        questions: [],
        lastLogin: Date.now(),
        lockoutDurationSeconds: 86400 
    },
    generation: {
        temperature: 1.0,
        topP: 0.95,
        topK: 40,
        maxOutputTokens: 8192,
        stream: false, 
        thinkingBudget: 0, 
        stripThoughts: false,
        frequencyPenalty: 0,
        googleSearch: false
    },
    scripts: {
        inputFilterEnabled: false,
        inputFilterCode: '',
        outputFilterEnabled: false,
        outputFilterCode: ''
    },
    enableKeyGrouping: false,
    keyGroups: []
  });

  const [toasts, setToasts] = useState<ToastMessage[]>([]);
  const [dialog, setDialog] = useState<DialogConfig>({
      isOpen: false,
      type: 'alert',
      title: '',
      onConfirm: () => {}
  });

  const [llmService, setLlmService] = useState<LLMService | null>(null);
  const abortControllerRef = useRef<AbortController | null>(null);
  const isProcessingRef = useRef(false);

  // --- 辅助工具函数 ---
  const addToast = (message: string, type: 'success' | 'error' | 'info' | 'warning' = 'info') => {
      setToasts(prev => [...prev, { id: uuidv4(), message, type }]);
  };

  const removeToast = (id: string) => {
      setToasts(prev => prev.filter(t => t.id !== id));
  };

  const showDialog = (config: Partial<DialogConfig> & { title: string, onConfirm: (value?: string) => void }) => {
      setDialog({
          isOpen: true,
          type: config.type || 'alert',
          title: config.title,
          message: config.message,
          inputValue: config.inputValue,
          inputPlaceholder: config.inputPlaceholder,
          onConfirm: config.onConfirm,
          onCancel: config.onCancel
      });
  };

  const closeDialog = () => {
      setDialog(prev => ({ ...prev, isOpen: false }));
  };

  const safeJsonParse = (str: string | null, fallback: any = null) => {
    if (!str || !str.trim()) return fallback;
    try {
      return JSON.parse(str);
    } catch (e) {
      console.warn("Failed to parse JSON from storage:", e);
      return fallback;
    }
  };

  /**
   * 节点 1: 挂载初始化
   * 从 LocalStorage 加载所有持久化数据，包括密钥、设置和会话历史。
   */
  useEffect(() => {
    const storedKeys = localStorage.getItem(STORAGE_KEYS_KEY);
    const oldKeysV3 = localStorage.getItem('gemini_omnichat_keys_v3');
    const oldSettingsStr = localStorage.getItem('gemini_omnichat_settings_v8');
    const oldSettings = safeJsonParse(oldSettingsStr);
    const globalModel = oldSettings?.model || DEFAULT_MODEL;
    const globalBaseUrl = oldSettings?.openAIBaseUrl || 'https://api.openai.com/v1';

    let initialKeys: KeyConfig[] = [];

    if (storedKeys) {
      initialKeys = safeJsonParse(storedKeys, []);
    } else if (oldKeysV3) {
      const parsed = safeJsonParse(oldKeysV3, []);
      initialKeys = parsed.map((k: any) => ({
          ...k,
          model: globalModel,
          baseUrl: k.provider === 'openai' ? globalBaseUrl : ''
      }));
    } else if (ENV_KEY) {
      initialKeys = ENV_KEY.split(',').map(k => k.trim()).filter(Boolean).map(k => ({
        id: uuidv4(),
        key: k,
        provider: 'google' as ModelProvider,
        isActive: true,
        usageLimit: 5, 
        isRateLimited: false,
        lastUsed: 0,
        model: DEFAULT_MODEL
      }));
    }
    setApiKeys(initialKeys);

    const storedSettings = localStorage.getItem(STORAGE_SETTINGS_KEY);
    let loadedSettings = settings;
    let loadedKnownModels = DEFAULT_KNOWN_MODELS;

    const storedKnownModels = localStorage.getItem(STORAGE_KNOWN_MODELS_KEY);
    if (storedKnownModels) {
        // Merge stored models with defaults to ensure new defaults appear
        const parsedStoredModels = safeJsonParse(storedKnownModels, []);
        // Create a map for easy lookup by name
        const storedModelMap = new Map(parsedStoredModels.map((m: any) => [m.name, m]));

        // Start with defaults
        const mergedModels = [...DEFAULT_KNOWN_MODELS];

        // Add any stored models that are NOT in defaults
        parsedStoredModels.forEach((m: any) => {
            if (!mergedModels.find(dm => dm.name === m.name)) {
                mergedModels.push(m);
            }
        });

        loadedKnownModels = mergedModels;
    }

    if (storedSettings) {
      const parsedSettings = safeJsonParse(storedSettings);
      if (parsedSettings) {
          if (parsedSettings.knownModels && !storedKnownModels) {
              loadedKnownModels = parsedSettings.knownModels;
          }
          if ('knownModels' in parsedSettings) delete parsedSettings.knownModels;
          loadedSettings = { ...settings, ...parsedSettings };
      }
    } 
    setSettings(loadedSettings);
    setKnownModels(loadedKnownModels);

    const effectiveKeys = initialKeys.map(k => {
        if (!k.groupId) return k;
        const group = loadedSettings.keyGroups?.find(g => g.id === k.groupId);
        if (group && group.isActive === false) return { ...k, isActive: false };
        return k;
    });

    // 初始化核心 LLM 服务
    setLlmService(new LLMService(
        effectiveKeys, 
        {
            onKeyError: (id, errorCode, isFatal = true) => {
                setApiKeys(prev => prev.map(k => {
                    if (k.id !== id) return k;
                    if (isFatal) return { ...k, isActive: false, lastErrorCode: errorCode };
                    else return { ...k, isRateLimited: true, lastUsed: Date.now(), lastErrorCode: errorCode };
                }));
                // Only toast on fatal errors here, LLMService handles other status messages
                if (isFatal) addToast(`${t('error.key_auto_disabled', loadedSettings.language)}${errorCode ? ` (${errorCode})` : ''}`, 'error');
            },
            onStatusMessage: (msg, type) => addToast(msg, type)
        }
    ));

    // 安全锁检查
    if (loadedSettings.security.enabled) {
        const lockoutThresholdMs = (loadedSettings.security.lockoutDurationSeconds || 86400) * 1000;
        if (Date.now() - (loadedSettings.security.lastLogin || 0) > lockoutThresholdMs) setIsLocked(true);
        else setSettings({ ...loadedSettings, security: { ...loadedSettings.security, lastLogin: Date.now() } });
    }

    // 会话恢复
    const storedSessions = localStorage.getItem(STORAGE_SESSIONS_KEY);
    const storedActiveId = localStorage.getItem(STORAGE_ACTIVE_SESSION_KEY);

    if (storedSessions) {
      const parsedSessions = safeJsonParse(storedSessions, []) as ChatSession[];
      if (parsedSessions.length > 0) {
        setSessions(parsedSessions);
        const targetId = (storedActiveId && parsedSessions.find(s => s.id === storedActiveId)) ? storedActiveId : parsedSessions[0].id;
        setActiveSessionId(targetId);
        setMessages(parsedSessions.find(s => s.id === targetId)?.messages || []);
      } else createNewSession();
    } else createNewSession();
  }, []);

  const createNewSession = () => {
    const newId = uuidv4();
    const newSession: ChatSession = {
      id: newId,
      title: t('msg.new_chat_title', settings.language),
      messages: [],
      createdAt: Date.now(),
      memory: '' // Initialize with empty memory
    };
    setSessions(prev => [newSession, ...prev]);
    setActiveSessionId(newId);
    setMessages([]);
  };

  /**
   * 节点 2: 数据同步
   * 监听状态变动并同步至服务层或持久化存储。
   */
  useEffect(() => {
    const effectiveKeys = apiKeys.map(k => {
        if (!k.groupId) return k;
        const group = settings.keyGroups?.find(g => g.id === k.groupId);
        if (group && group.isActive === false) return { ...k, isActive: false };
        return k;
    });

    if (llmService) llmService.updateKeys(effectiveKeys, settings.keyGroups || []);
    localStorage.setItem(STORAGE_KEYS_KEY, JSON.stringify(apiKeys));
  }, [apiKeys, llmService, settings.keyGroups]);

  useEffect(() => {
    localStorage.setItem(STORAGE_SETTINGS_KEY, JSON.stringify(settings));
    const root = document.documentElement;
    root.classList.remove('dark', 'theme-dark', 'theme-light', 'theme-twilight', 'theme-sky', 'theme-pink', 'theme-sunrise', 'theme-lime', 'theme-panda', 'theme-chocolate', 'theme-vscode-light', 'theme-vscode-dark');
    root.classList.add(`theme-${settings.theme}`);
    if (['dark', 'twilight', 'vscode-dark', 'chocolate'].includes(settings.theme)) root.classList.add('dark');
  }, [settings]);

  useEffect(() => {
    localStorage.setItem(STORAGE_KNOWN_MODELS_KEY, JSON.stringify(knownModels));
  }, [knownModels]);

  useEffect(() => {
    if (!activeSessionId) return;
    setSessions(prev => {
      const idx = prev.findIndex(s => s.id === activeSessionId);
      if (idx === -1) return prev;
      // Only update if messages have changed to avoid unnecessary cycles
      if (prev[idx].messages === messages) return prev;

      const updated = [...prev];
      updated[idx] = { ...updated[idx], messages };
      return updated;
    });
  }, [messages, activeSessionId]);

  useEffect(() => {
    if (sessions.length > 0) localStorage.setItem(STORAGE_SESSIONS_KEY, JSON.stringify(sessions));
  }, [sessions]);

  useEffect(() => {
    if (activeSessionId) localStorage.setItem(STORAGE_ACTIVE_SESSION_KEY, activeSessionId);
  }, [activeSessionId]);

  /**
   * 节点 3: 消息处理逻辑
   * 处理流式响应并将其分片渲染至 UI。
   */
  const triggerBotResponse = async (historyBefore: Message[], userMessage: Message) => {
    if (!llmService) return;
    setIsLoading(true);

    if (abortControllerRef.current) abortControllerRef.current.abort();
    const controller = new AbortController();
    abortControllerRef.current = controller;

    const tempBotId = uuidv4();
    const botMessage: Message = {
      id: tempBotId,
      role: Role.MODEL,
      text: '',
      timestamp: Date.now()
    };

    setMessages([...historyBefore, userMessage, botMessage]);

    const startTime = Date.now();

    try {
      // 1. Get Global System Prompt
      const globalSystemInstruction = settings.systemPrompts.filter(p => p.isActive).map(p => p.content).join('\n\n');

      // 2. Get Session Specific Memory
      // Note: We access sessions state directly here. It might lag slightly behind if updated very recently in same tick, 
      // but memory updates usually happen via dedicated user action.
      const currentSession = sessions.find(s => s.id === activeSessionId);
      const sessionMemory = currentSession?.memory || '';

      // 3. Combine Instructions (Memory acts as a high-priority system context)
      // Using array filter to remove empty strings before joining
      const finalSystemInstruction = [globalSystemInstruction, sessionMemory].filter(Boolean).join('\n\n');

      let historyForApi = historyBefore.filter(m => m.id !== userMessage.id);

      if (settings.generation.stripThoughts) {
        historyForApi = historyForApi.map(msg => {
            if (msg.role === Role.MODEL && msg.text.includes('<think>')) {
                 const cleanText = msg.text.replace(/<think>[\s\S]*?(?:<\/think>|$)/g, '').trim();
                 return { ...msg, text: cleanText };
            }
            return msg;
        });
      }

      let contextToSend = historyForApi;
      if (settings.historyContextLimit > 0 && historyForApi.length > settings.historyContextLimit) {
          contextToSend = historyForApi.slice(-settings.historyContextLimit);
      }

      // 执行流式调用
      const { text: fullText, usedKeyIndex, provider, usedModel, groundingMetadata } = await llmService.streamChatResponse(
        '', 
        contextToSend, 
        userMessage.text, 
        userMessage.images, 
        finalSystemInstruction,
        settings.generation,
        (chunkText) => {
           let processedChunk = chunkText;
           if (settings.scripts?.outputFilterEnabled && settings.scripts.outputFilterCode) {
               processedChunk = executeFilterScript(settings.scripts.outputFilterCode, chunkText, { role: 'model', history: [...historyBefore, userMessage] });
           }
           setMessages(prev => prev.map(msg => msg.id === tempBotId ? { ...msg, text: processedChunk } : msg));
        },
        controller.signal,
        settings.language
      );

      const executionTime = Date.now() - startTime;
      let processedFinalText = fullText;

      if (settings.scripts?.outputFilterEnabled && settings.scripts.outputFilterCode) {
          processedFinalText = executeFilterScript(settings.scripts.outputFilterCode, fullText, { role: 'model', history: [...historyBefore, userMessage] });
      }

      // Resolve Group Name
      let groupName: string | undefined;
      if (usedKeyIndex && usedKeyIndex > 0 && usedKeyIndex <= apiKeys.length) {
          const usedKey = apiKeys[usedKeyIndex - 1];
          if (usedKey && usedKey.groupId) {
              const group = settings.keyGroups?.find(g => g.id === usedKey.groupId);
              if (group) groupName = group.name;
          }
      }

      setMessages(prev => 
        prev.map(msg => 
          msg.id === tempBotId ? { 
              ...msg, 
              text: processedFinalText, 
              keyIndex: usedKeyIndex, 
              provider: provider, 
              model: usedModel, 
              executionTime: executionTime,
              groupName: groupName,
              groundingMetadata: groundingMetadata // Store metadata
          } : msg
        )
      );

      // --- Auto-Generate Chat Memory Logic ---
      if (settings.enableAutoMemory && !controller.signal.aborted) {
          // Check if we hit the interval. We add 2 (User + AI) to current history length before this turn.
          // Or simpler: check total message count including the new ones.
          const totalMessages = historyBefore.length + 2; 
          const interval = settings.autoMemoryInterval || 20;

          if (totalMessages > 0 && totalMessages % interval === 0) {
              // Trigger memory update silently in background
              generateAutoMemory(sessionMemory, userMessage.text, processedFinalText);
          }
      }

    } catch (error: any) {
      if (error.message !== "Aborted by user") {
         const errorMessage: Message = {
            id: uuidv4(),
            role: Role.MODEL,
            text: `${t('action.error', settings.language)}: ${error.message || t('error.unexpected_error', settings.language)}`,
            timestamp: Date.now(),
            isError: true,
            executionTime: Date.now() - startTime
         };
         setMessages(prev => prev.filter(m => m.id !== tempBotId).concat(errorMessage));
      }
    } finally {
      setIsLoading(false);
      abortControllerRef.current = null;
    }
  };

  /**
   * Helper function to update conversation memory automatically in background.
   */
  const generateAutoMemory = async (currentMemory: string, userText: string, aiText: string) => {
      if (!llmService) return;

      // Construct a meta-prompt for memory consolidation
      // Updated to focus on "key facts, conclusions, and context" rather than just role/settings
      const memoryPrompt = `
Existing Memory: ${currentMemory}

User Input: ${userText.slice(0, 500)}
AI Response: ${aiText.slice(0, 500)}

Instruction: Analyze the exchange and update the Existing Memory. Focus on preserving key facts, user preferences, important conclusions, and context. Remove obsolete details. Keep it concise. Return ONLY the updated memory text.
`;

      try {
          // We use streamChatResponse but ignore the chunks, just wait for final text.
          // Using a blank system instruction for this meta-task.
          // IMPORTANT: Disable search for memory generation to save tokens/latency
          const memoryGenConfig = { ...settings.generation, stream: false, googleSearch: false };

          const { text: newMemory } = await llmService.streamChatResponse(
              '', 
              [], 
              memoryPrompt, 
              undefined, 
              undefined, 
              memoryGenConfig, // Use non-streaming and no-search
              undefined,
              undefined,
              settings.language
          );

          if (newMemory && newMemory.trim()) {
              handleUpdateSessionMemory(newMemory.trim());
              addToast(t('msg.memory_updated', settings.language), 'info');
          }
      } catch (e) {
          // Silent fail for background tasks, or maybe log to console
          console.warn("Auto-memory generation failed", e);
      }
  };

  const handleStopGeneration = () => {
      if (abortControllerRef.current) {
          abortControllerRef.current.abort();
          abortControllerRef.current = null;
          setIsLoading(false);
      }
  };

  const handleSendMessage = async () => {
    if (!llmService || isProcessingRef.current) return;
    if (!input.trim() && inputImages.length === 0) return;

    if (apiKeys.filter(k => k.isActive).length === 0) {
      setIsSettingsOpen(true);
      return;
    }

    isProcessingRef.current = true; 

    let processedInput = input.trim();
    if (settings.scripts?.inputFilterEnabled && settings.scripts.inputFilterCode) {
        processedInput = executeFilterScript(settings.scripts.inputFilterCode, processedInput, { role: 'user', history: messages });
    }

    const newMessage: Message = {
      id: uuidv4(),
      role: Role.USER,
      text: processedInput,
      images: inputImages.length > 0 ? [...inputImages] : undefined, 
      timestamp: Date.now()
    };

    setMessages(prev => [...prev, newMessage]);
    setInput('');
    setInputImages([]); 

    try {
        await triggerBotResponse(messages, newMessage);
    } finally {
        isProcessingRef.current = false; 
    }
  };

  /**
   * 节点 4: 加载对话功能修复与增强
   * 将对话作为新会话导入，而不是覆盖当前会话，避免用户误操作。
   */
  const handleLoadSession = (loadedMessages: any[], title?: string) => {
      handleStopGeneration();

      // 生成新的会话对象
      const newId = uuidv4();
      const newSession: ChatSession = {
          id: newId,
          title: title || t('msg.new_chat_title', settings.language),
          messages: loadedMessages,
          createdAt: Date.now(),
          memory: '' // Import defaults to empty unless we import full session objects later
      };

      // 插入到会话列表最前端并立即切换
      setSessions(prev => [newSession, ...prev]);
      setActiveSessionId(newId);
      setMessages(loadedMessages);
      setInput('');

      // 使用更明确的“对话已导入”提示
      addToast(t('success.chat_import', settings.language) || t('msg.config_imported', settings.language), 'success');
  };

  const handleUpdateSessionMemory = (newMemory: string) => {
      setSessions(prev => prev.map(s => s.id === activeSessionId ? { ...s, memory: newMemory } : s));
  };

  const handleSaveChat = () => {
    const activeSession = sessions.find(s => s.id === activeSessionId);
    const title = activeSession?.title || t('label.session', settings.language);
    const safeTitle = title.replace(/[^a-z0-9\u4e00-\u9fa5]/gi, '_').substring(0, 50);
    const chatData = { 
        title, 
        date: new Date().toISOString(), 
        messages,
        memory: activeSession?.memory || '' // Export memory too
    };
    const blob = new Blob([JSON.stringify(chatData, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `OmniChat-${safeTitle}.json`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  const handleSelectSession = (sessionId: string) => {
    if (sessionId === activeSessionId) { setIsMobileMenuOpen(false); return; }
    handleStopGeneration();
    const session = sessions.find(s => s.id === sessionId);
    if (session) {
      setActiveSessionId(sessionId);
      setMessages(session.messages);
      setInput('');
      setIsMobileMenuOpen(false);
    }
  };

  const activeKeysCount = apiKeys.filter(k => k.isActive).length;
  const currentSession = sessions.find(s => s.id === activeSessionId);
  const currentSessionTitle = currentSession?.title || t('app.title', settings.language);
  const currentSessionMemory = currentSession?.memory || '';

  if (isLocked) return (
    <div className={`${['dark', 'twilight', 'vscode-dark', 'chocolate'].includes(settings.theme) ? 'dark' : ''}`}>
        <Suspense fallback={<div className="flex h-screen items-center justify-center bg-gray-100 dark:bg-gray-950"></div>}>
            <SecurityLock config={settings.security} onUnlock={() => setIsLocked(false)} lang={settings.language} theme={settings.theme} kirbyThemeColor={settings.kirbyThemeColor} />
        </Suspense>
    </div>
  );

  return (
    <div className={`flex h-screen font-sans ${['dark', 'twilight', 'vscode-dark', 'chocolate'].includes(settings.theme) ? 'dark' : ''}`}>
      <ToastContainer toasts={toasts} removeToast={removeToast} />
      <CustomDialog config={dialog} onClose={closeDialog} lang={settings.language} />

      <div className="flex w-full h-full bg-transparent text-gray-900 dark:text-gray-100 transition-colors duration-300">
        <Sidebar 
            sessions={sessions} activeSessionId={activeSessionId} activeKeysCount={activeKeysCount} 
            language={settings.language} theme={settings.theme} kirbyThemeColor={settings.kirbyThemeColor}
            onNewChat={() => { handleStopGeneration(); createNewSession(); setIsMobileMenuOpen(false); }} 
            onSelectSession={handleSelectSession} 
            onDeleteSession={(e, id) => {
                e.stopPropagation();
                const newSessions = sessions.filter(s => s.id !== id);
                setSessions(newSessions);
                if (activeSessionId === id) {
                   handleStopGeneration();
                   if (newSessions.length > 0) {
                     setActiveSessionId(newSessions[0].id);
                     setMessages(newSessions[0].messages);
                   } else createNewSession();
                }
            }}
            onOpenSettings={() => setIsSettingsOpen(true)}
        />

        <Suspense fallback={null}>
            <MobileMenu 
                isOpen={isMobileMenuOpen} sessions={sessions} activeSessionId={activeSessionId} language={settings.language}
                onClose={() => setIsMobileMenuOpen(false)} onNewChat={() => { handleStopGeneration(); createNewSession(); setIsMobileMenuOpen(false); }} 
                onSelectSession={handleSelectSession}
                onDeleteSession={(e, id) => {
                    e.stopPropagation();
                    const newSessions = sessions.filter(s => s.id !== id);
                    setSessions(newSessions);
                    if (activeSessionId === id) {
                       handleStopGeneration();
                       if (newSessions.length > 0) {
                         setActiveSessionId(newSessions[0].id);
                         setMessages(newSessions[0].messages);
                       } else createNewSession();
                    }
                }} 
                onOpenSettings={() => setIsSettingsOpen(true)}
            />
        </Suspense>

        <main className="flex-1 flex flex-col relative h-full min-w-0 overflow-hidden">
          <Header 
             currentSessionTitle={currentSessionTitle} 
             isSummarizing={isSummarizing} 
             hasMessages={messages.length > 0}
             language={settings.language}
             currentSessionMemory={currentSessionMemory}
             onRename={() => {
                const session = sessions.find(s => s.id === activeSessionId);
                showDialog({
                    type: 'input',
                    title: t('msg.rename_chat', settings.language),
                    inputValue: session?.title || '',
                    onConfirm: (newTitle) => {
                        if (newTitle && newTitle.trim()) setSessions(prev => prev.map(s => s.id === activeSessionId ? { ...s, title: newTitle.trim() } : s));
                    }
                });
             }} 
             onSummarize={async () => {
                if (messages.length === 0 || !llmService) return;
                setIsSummarizing(true); 
                try {
                    const historyText = messages.map(m => `${m.role === Role.USER ? 'User' : 'Model'}: ${m.text}`).join('\n');
                    const prompt = t('msg.summarize_prompt', settings.language) + '\n\n' + historyText;
                    const { text } = await llmService.streamChatResponse('', [], prompt, [], undefined, settings.generation, undefined, undefined, settings.language);
                    const newTitle = text.trim().replace(/['"]/g, '').replace(/\.$/, '').replace(/\*\*/g, ''); 
                    if (newTitle) {
                        setSessions(prev => prev.map(s => s.id === activeSessionId ? { ...s, title: newTitle } : s));
                        addToast(t('action.ok', settings.language), 'success');
                    }
                } catch (e) {
                    addToast(t('msg.summarize_error', settings.language), 'error');
                } finally { setIsSummarizing(false); }
             }}
             onOpenMobileMenu={() => setIsMobileMenuOpen(true)} 
             onNewChat={() => { handleStopGeneration(); createNewSession(); }} 
             onClearChat={() => {
                if (messages.length === 0) return;
                showDialog({
                    type: 'confirm',
                    title: t('action.clear_chat', settings.language),
                    message: t('msg.confirm_clear_chat', settings.language),
                    onConfirm: () => {
                        handleStopGeneration();
                        setMessages([]);
                        setSessions(prev => prev.map(s => s.id === activeSessionId ? { ...s, messages: [] } : s));
                    }
                });
             }}
             onOpenSettings={() => setIsSettingsOpen(true)} 
             onSaveChat={handleSaveChat} 
             onLoadSession={handleLoadSession}
             onUpdateMemory={handleUpdateSessionMemory}
             onShowToast={addToast}
          />

          <ChatInterface 
              messages={messages} isLoading={isLoading} 
              onEditMessage={(id, newText) => setMessages(prev => prev.map(msg => msg.id === id ? { ...msg, text: newText } : msg))} 
              onDeleteMessage={(id) => setMessages(prev => prev.filter(msg => msg.id !== id))} 
              onRegenerate={async (id) => {
                if (!llmService) return;
                const index = messages.findIndex(m => m.id === id);
                if (index === -1) return;
                const targetMsg = messages[index];
                if (targetMsg.role === Role.USER) {
                   await triggerBotResponse(messages.slice(0, index), targetMsg);
                } else {
                  let userMsgIndex = index - 1;
                  while (userMsgIndex >= 0 && messages[userMsgIndex].role !== Role.USER) userMsgIndex--;
                  if (userMsgIndex !== -1) await triggerBotResponse(messages.slice(0, userMsgIndex), messages[userMsgIndex]);
                }
              }} 
              language={settings.language} fontSize={settings.fontSize} 
              textWrapping={settings.textWrapping} bubbleTransparency={settings.bubbleTransparency}
              showModelName={settings.showModelName} showGroupName={settings.showGroupName} showResponseTimer={settings.showResponseTimer} theme={settings.theme}
              kirbyThemeColor={settings.kirbyThemeColor} onShowToast={addToast} smoothAnimation={settings.smoothAnimation}
              avatarVisibility={settings.avatarVisibility}
          />

          <div className="absolute bottom-0 left-0 right-0 z-20 bg-gradient-to-t from-white via-white to-transparent dark:from-gray-950 dark:via-gray-950 dark:to-transparent pt-10 pb-0">
             <ChatInput 
                input={input} setInput={setInput} inputImages={inputImages} setInputImages={setInputImages}
                onSend={handleSendMessage} onStop={handleStopGeneration} isLoading={isLoading} isDisabled={activeKeysCount === 0}
                fontSize={settings.fontSize} language={settings.language} activeKeysCount={activeKeysCount} showTokenUsage={settings.showTokenUsage}
                history={messages} historyLimit={settings.historyContextLimit} 
                onGetTokenCount={async (currentInput) => {
                    if (!llmService || apiKeys.length === 0) return 0;
                    const activeKey = apiKeys.find(k => k.isActive);
                    if (!activeKey) return 0;
                    return await llmService.countTokens(activeKey, messages, currentInput, settings.systemPrompts.filter(p => p.isActive).map(p => p.content).join('\n\n'));
                }} 
                theme={settings.theme}
                isSearchEnabled={settings.generation.googleSearch}
                onToggleSearch={(enabled) => setSettings({ ...settings, generation: { ...settings.generation, googleSearch: enabled } })}
             />
             <div className="text-center text-[10px] text-gray-400 dark:text-gray-600 pb-0 select-none">
                {t('footer.ai_generated', settings.language)}{APP_VERSION}
             </div>
          </div>
        </main>

        <Suspense fallback={null}>
            <SettingsModal 
                isOpen={isSettingsOpen} onClose={() => setIsSettingsOpen(false)} apiKeys={apiKeys} onUpdateKeys={setApiKeys} 
                settings={settings} onUpdateSettings={setSettings} llmService={llmService} onShowToast={addToast}
                onShowDialog={showDialog} knownModels={knownModels} onUpdateKnownModels={setKnownModels}
            />
        </Suspense>
      </div>
    </div>
  );
};

export default App;

import { Message, KeyConfig, GenerationConfig, ModelProvider, ModelInfo, Language, KeyGroup } from "../types";
import { OpenAIService } from "./openaiService";
import { GoogleService } from "./googleService";
import { OllamaService } from "./ollamaService";
import { t } from "../utils/i18n";

/**
 * 队列任务接口定义
 */
interface RequestTask {
  execute: () => Promise<any>;
  resolve: (value: any) => void;
  reject: (reason?: any) => void;
  abortSignal?: AbortSignal;
}

interface LLMServiceCallbacks {
    onKeyError?: (id: string, errorCode?: string, isFatal?: boolean) => void;
    onStatusMessage?: (message: string, type: 'info' | 'warning' | 'error' | 'success') => void;
}

/**
 * LLM 核心服务类：处理多提供商交互。
 * 包含：API 密钥轮询、负载均衡、请求队列处理。
 */
export class LLMService {
  private keys: KeyConfig[] = [];
  private keyGroups: KeyGroup[] = [];
  private keyIndex: number = 0; // 当前轮询到的 Key 索引
  private keyUsageCount: number = 0; // 当前 Key 已使用的次数

  // 队列管理状态：确保 API 请求按顺序处理，避免高并发冲突
  private requestQueue: RequestTask[] = [];
  private isProcessingQueue: boolean = false;

  private openAIService: OpenAIService;
  private googleService: GoogleService;
  private ollamaService: OllamaService;

  private onKeyError?: (id: string, errorCode?: string, isFatal?: boolean) => void;
  private onStatusMessage?: (message: string, type: 'info' | 'warning' | 'error' | 'success') => void;

  constructor(
      initialKeys: KeyConfig[], 
      callbacksOrOnError?: LLMServiceCallbacks | ((id: string, errorCode?: string, isFatal?: boolean) => void)
  ) {
    this.updateKeys(initialKeys);
    this.openAIService = new OpenAIService();
    this.googleService = new GoogleService();
    this.ollamaService = new OllamaService();

    if (typeof callbacksOrOnError === 'function') {
        this.onKeyError = callbacksOrOnError;
    } else if (callbacksOrOnError) {
        this.onKeyError = callbacksOrOnError.onKeyError;
        this.onStatusMessage = callbacksOrOnError.onStatusMessage;
    }
  }

  /**
   * 更新 API 密钥池
   */
  public updateKeys(newKeys: KeyConfig[], keyGroups: KeyGroup[] = []) {
    this.keys = newKeys;
    this.keyGroups = keyGroups;
    // 索引越界安全检查
    if (this.keyIndex >= this.keys.length) {
        this.keyIndex = 0;
        this.keyUsageCount = 0;
    }
  }

  private getGroupName(groupId?: string): string | undefined {
    if (!groupId) return undefined;
    return this.keyGroups.find(g => g.id === groupId)?.name;
  }

  /**
   * 将任务推入队列并触发处理逻辑
   */
  private async enqueueTask<T>(execute: () => Promise<T>, abortSignal?: AbortSignal): Promise<T> {
    return new Promise((resolve, reject) => {
      if (abortSignal?.aborted) {
        return reject(new Error("Aborted by user"));
      }

      this.requestQueue.push({
        execute,
        resolve,
        reject,
        abortSignal
      });

      this.processQueue();
    });
  }

  /**
   * 顺序处理队列中的任务 (FIFO)
   */
  private async processQueue() {
    if (this.isProcessingQueue || this.requestQueue.length === 0) return;

    this.isProcessingQueue = true;

    while (this.requestQueue.length > 0) {
      const task = this.requestQueue.shift();
      if (!task) continue;

      if (task.abortSignal?.aborted) {
        task.reject(new Error("Aborted by user"));
        continue;
      }

      try {
        const result = await task.execute();
        task.resolve(result);
      } catch (error) {
        task.reject(error);
      }
    }

    this.isProcessingQueue = false;
  }

  /**
   * 获取模型列表
   */
  public async listModels(keyConfig: KeyConfig): Promise<ModelInfo[]> {
    return this.enqueueTask(async () => {
      if (keyConfig.provider === 'openai') {
          if (!keyConfig.baseUrl) throw new Error("Base URL is required for OpenAI provider");
          return await this.openAIService.listModels(keyConfig.key, keyConfig.baseUrl);
      } else if (keyConfig.provider === 'ollama') {
          return await this.ollamaService.listModels(keyConfig.baseUrl || '', keyConfig.key);
      } else {
          return await this.googleService.listModels(keyConfig.key);
      }
    });
  }

  /**
   * 测试连接
   */
  public async testConnection(keyConfig: KeyConfig): Promise<boolean> {
    return this.enqueueTask(async () => {
      const modelToUse = keyConfig.model || (keyConfig.provider === 'openai' ? 'gpt-3.5-turbo' : 'gemini-2.5-flash');
      try {
          if (keyConfig.provider === 'openai') {
              if (!keyConfig.baseUrl) return false;
              return await this.openAIService.testChat(keyConfig.key, keyConfig.baseUrl, modelToUse);
          } else if (keyConfig.provider === 'ollama') {
              return await this.ollamaService.testConnection(keyConfig.baseUrl || '', keyConfig.key);
          } else {
              return await this.googleService.testConnection(keyConfig.key, modelToUse);
          }
      } catch (e) {
          return false;
      }
    });
  }

  /**
   * 核心算法：轮询策略
   * 寻找下一个可用的 API 密钥，考虑：活跃状态、速率限制冷却时间、单个 Key 的轮询配额。
   */
  private getNextAvailableKey(lang: Language): KeyConfig {
    const activeKeys = this.keys.filter(k => k.isActive);

    if (activeKeys.length === 0) {
      throw new Error(t('error.no_active_keys', lang));
    }

    const attempts = activeKeys.length;
    let selectedKey: KeyConfig | null = null;
    let selectedIndex = -1;

    for (let i = 0; i < attempts; i++) {
        const idx = (this.keyIndex + i) % activeKeys.length;
        const candidate = activeKeys[idx];

        // 检查冷却时间：如果被 429 限制，进入 1 分钟冷却期
        if (candidate.isRateLimited && Date.now() - candidate.lastUsed < 60000) {
            continue; 
        }

        // 检查轮询配额：如果当前 Key 还没用够设定的次数，继续用它
        if (i === 0 && this.keyUsageCount < (candidate.usageLimit || 1)) {
             selectedKey = candidate;
             selectedIndex = idx;
             break;
        }

        // 切换到下一个 Key
        if (i > 0) {
            selectedKey = candidate;
            selectedIndex = idx;
            break;
        }
    }

    // 如果所有 Key 都因为某种原因被跳过，强制选择当前索引的下一个
    if (!selectedKey) {
        selectedIndex = (this.keyIndex + 1) % activeKeys.length;
        selectedKey = activeKeys[selectedIndex];
    }

    // 如果发生了索引切换，重置单密钥使用计数
    if (this.keyIndex !== selectedIndex) {
        this.keyIndex = selectedIndex;
        this.keyUsageCount = 0;
    }

    this.keyUsageCount++;
    return selectedKey;
  }

  private getKeyDisplayIndex(id: string): number {
      return this.keys.findIndex(k => k.id === id) + 1;
  }

  /**
   * 错误分级处理逻辑
   * 将 API 返回的原始错误转化为用户可读的本地化语言。
   */
  private getErrorMessage(error: any, lang: Language): string {
      const status = error.status || error.statusCode;
      const msg = error.message?.toLowerCase() || '';

      if (status === 401 || msg.includes('401') || msg.includes('invalid api key')) return t('error.invalid_api_key', lang);
      if (status === 402 || msg.includes('402') || msg.includes('billing')) return t('error.billing_required', lang);
      if (status === 403 || msg.includes('403') || msg.includes('permission denied')) return t('error.permission_denied', lang);
      if (status === 404 || msg.includes('404') || msg.includes('not found')) return t('error.model_not_found', lang);
      if (status === 429 || msg.includes('429') || msg.includes('quota') || msg.includes('rate limit')) return t('error.quota_exceeded', lang);
      if (status === 400 || msg.includes('400')) {
          if (msg.includes('safety') || error.isSafety) return t('error.safety_block', lang);
          if (msg.includes('context')) return t('error.context_length_exceeded', lang);
          return t('error.bad_request', lang);
      }
      if (status === 500 || status === 502 || status === 503 || msg.includes('500')) return t('error.server_error', lang);
      if (status === 0 || msg.includes('network') || msg.includes('fetch')) return t('error.network_issue', lang);

      return error.message || t('error.unexpected_error', lang);
  }

  /**
   * 节点 5: 核心重试与分发逻辑
   * 在发生非致命错误（如速率限制）时自动切换密钥并重试。
   */
  public async streamChatResponse(
    _ignoredGlobalModelId: string, 
    history: Message[],
    newMessage: string,
    images: string[] | undefined,
    systemInstruction: string | undefined,
    generationConfig: GenerationConfig,
    onChunk?: (text: string) => void,
    abortSignal?: AbortSignal,
    lang: Language = 'en'
  ): Promise<{ text: string, usedKeyIndex: number, provider: ModelProvider, usedModel: string, groundingMetadata?: any }> {

    return this.enqueueTask(async () => {
        const activeKeysCount = this.keys.filter(k => k.isActive).length;
        // 最大重试次数为活跃密钥数的 2 倍
        const maxRetries = Math.max(activeKeysCount * 2, 2); 
        let attempts = 0;
        const validHistory = history.filter(msg => (msg.text && msg.text.trim().length > 0) || (msg.images && msg.images.length > 0));

        let lastError: any = null;
        let lastGroupId: string | undefined = undefined;

        while (attempts < maxRetries) {
            let keyConfig: KeyConfig;
            try {
                keyConfig = this.getNextAvailableKey(lang);
            } catch (e: any) {
                throw e;
            }

            const currentKeyIndex = this.getKeyDisplayIndex(keyConfig.id);
            const currentGroupId = keyConfig.groupId;
            const groupName = this.getGroupName(currentGroupId);

            // Notify on switch (Retry or Rotation)
            // Skip notification for the very first attempt unless debugging, to be less noisy? 
            // The prompt asks for "Every key switch", so we include retries.
            if (attempts > 0) {
                let msg = t('msg.switching_key', lang).replace('{index}', currentKeyIndex.toString());
                // Detect Group Switch specifically
                if (currentGroupId && lastGroupId && currentGroupId !== lastGroupId && groupName) {
                     msg += ` (${t('msg.switching_group', lang).replace('{group}', groupName)})`;
                }
                this.onStatusMessage?.(msg, 'info');
            }

            lastGroupId = currentGroupId;

            const modelToUse = keyConfig.model || _ignoredGlobalModelId || 'gemini-3-flash-preview';

            try {
                let response: { text: string; groundingMetadata?: any } = { text: "", groundingMetadata: undefined };

                // 根据提供商分发请求
                if (keyConfig.provider === 'google' && modelToUse.toLowerCase().includes('imagen')) {
                     const imageMarkdown = await this.googleService.generateImage(keyConfig.key, modelToUse, newMessage);
                     response = { text: imageMarkdown, groundingMetadata: undefined };
                } 
                else if (keyConfig.provider === 'openai') {
                    if (!keyConfig.baseUrl) throw new Error(t('error.base_url_required', lang));
                    response = await this.openAIService.streamChat(
                        keyConfig.key, keyConfig.baseUrl, modelToUse, validHistory, 
                        newMessage, images, systemInstruction, generationConfig, onChunk, abortSignal
                    );
                } 
                else if (keyConfig.provider === 'ollama') {
                    response = await this.ollamaService.streamChat(
                        keyConfig.baseUrl || '', modelToUse, validHistory, 
                        newMessage, images, systemInstruction, generationConfig, keyConfig.key, onChunk, abortSignal
                    );
                } 
                else {
                    response = await this.googleService.streamChat(
                        keyConfig.key, modelToUse, validHistory, 
                        newMessage, images, systemInstruction, generationConfig, onChunk, abortSignal
                    );
                }

                return { 
                    text: response.text, 
                    usedKeyIndex: currentKeyIndex, 
                    provider: keyConfig.provider,
                    usedModel: modelToUse,
                    groundingMetadata: response.groundingMetadata
                };

            } catch (error: any) {
                if (abortSignal?.aborted) throw new Error("Aborted by user");

                lastError = error;
                let errorCode = 'Error';
                let statusCode = error.status || error.statusCode;

                if (!statusCode) {
                     const match = error.message?.match(/\b\d{3}\b/);
                     if (match) errorCode = match[0];
                     else if (error.message?.includes("Network")) errorCode = "Network";
                } else {
                    errorCode = statusCode.toString();
                }

                // Notify Error before switching
                const errorMessage = this.getErrorMessage(error, lang);
                this.onStatusMessage?.(
                    t('msg.key_error_verbose', lang)
                        .replace('{index}', currentKeyIndex.toString())
                        .replace('{error}', errorMessage), 
                    'error'
                );

                // 判断是否是致命错误：身份验证失败、计费问题、位置不支持等需要禁用密钥
                let isFatal = [401, 402, 403, 404].includes(statusCode);

                // 安全审核拦截不属于密钥问题，直接抛出给用户
                if (error.isSafety) {
                    throw new Error(this.getErrorMessage(error, lang));
                }

                if (this.onKeyError) {
                    this.onKeyError(keyConfig.id, errorCode, isFatal);
                }

                const localKey = this.keys.find(k => k.id === keyConfig.id);
                if (localKey) {
                    if (isFatal) localKey.isActive = false;
                    else {
                        // 速率限制错误：进入冷却
                        localKey.isRateLimited = true;
                        localKey.lastUsed = Date.now();
                        // 强制轮询配额用满，以便下次重试使用新 Key
                        this.keyUsageCount = 10000; 
                    }
                    localKey.lastErrorCode = errorCode;
                }

                if (this.keys.filter(k => k.isActive).length === 0) break; 

                attempts++;
                continue;
            }
        }

        if (lastError) throw new Error(this.getErrorMessage(lastError, lang));
        throw new Error(t('error.all_keys_failed', lang));
    }, abortSignal);
  }

  /**
   * Token 统计
   */
  public async countTokens(
      keyConfig: KeyConfig,
      history: Message[],
      newMessage: string,
      _ignoredSystemInstruction: string | undefined
  ): Promise<number> {
      return this.enqueueTask(async () => {
          if (keyConfig.provider !== 'google') return -1;
          return await this.googleService.countTokens(
              keyConfig.key, keyConfig.model || 'gemini-3-flash-preview', history, newMessage
          );
      });
  }
}

import React, { useRef, useState, useEffect, useLayoutEffect, useMemo } from 'react';
import { User, X, Save, Edit2, RefreshCw, Trash2, Clock, Folder } from 'lucide-react';
import { Message, Role, Language, TextWrappingMode, Theme, AvatarVisibility } from '../types';
import { t } from '../utils/i18n';
import { KirbyIcon } from './Kirby';
import { AutoResizeTextarea } from './ui/AutoResizeTextarea';
import { MessageContent } from './message/MessageContent';

interface ChatMessageProps {
  msg: Message;
  isEditing: boolean;
  isConfirmingDelete: boolean;
  isLoading: boolean;
  bubbleTransparency: number;
  textWrapping: TextWrappingMode;
  fontSize: number;
  showModelName: boolean;
  showGroupName?: boolean;
  showResponseTimer?: boolean;
  language: Language;
  theme: Theme;
  kirbyThemeColor: boolean;
  onEditMessage: (id: string, newText: string) => void;
  onDeleteMessage: (id: string) => void;
  onRegenerate: (id: string) => void;
  setEditingId: (id: string | null) => void;
  setConfirmDeleteId: (id: string | null) => void;
  startEditing: (msg: Message) => void;
  deleteTimerRef: React.MutableRefObject<ReturnType<typeof setTimeout> | null>;
  onShowToast: (message: string, type: 'success' | 'error' | 'info') => void;
  smoothAnimation?: boolean;
  isLast?: boolean;
  onScrollToBottom?: () => void;
  avatarVisibility: AvatarVisibility;
  onViewImage?: (url: string) => void;
}

export const ChatMessage: React.FC<ChatMessageProps> = React.memo(({
  msg,
  isEditing,
  isConfirmingDelete,
  isLoading,
  bubbleTransparency,
  textWrapping,
  fontSize,
  showModelName,
  showGroupName,
  showResponseTimer = false,
  language,
  theme,
  kirbyThemeColor,
  onEditMessage,
  onDeleteMessage,
  onRegenerate,
  setEditingId,
  setConfirmDeleteId,
  startEditing,
  deleteTimerRef,
  onShowToast,
  smoothAnimation = true,
  isLast = false,
  onScrollToBottom,
  avatarVisibility,
  onViewImage
}) => {
  const safeText = msg.text || '';
  const [editText, setEditText] = useState(safeText);
  const [displayedText, setDisplayedText] = useState(safeText);
  const targetTextRef = useRef(safeText);
  const animationRef = useRef<number>(0);

  const isVSCodeTheme = theme === 'vscode-light' || theme === 'vscode-dark';
  const containerClass = isVSCodeTheme ? 'max-w-[85rem]' : 'max-w-5xl';

  // 检测消息是否为生成的图片（Markdown 图片且包含 Data URI）
  // 对于生成的图片跳过动画，避免 base64 源码闪烁
  const isGeneratedImage = useMemo(() => {
      const trimmed = safeText.trim();
      return msg.role === Role.MODEL && trimmed.startsWith('![') && trimmed.includes('(data:image/');
  }, [safeText, msg.role]);

  // --- 动画逻辑 ---
  useEffect(() => {
    targetTextRef.current = safeText;
    // 如果关闭动画、不是 AI 消息、错误消息、正在编辑或生成的图片，则直接显示完整文本
    if (!smoothAnimation || msg.role !== Role.MODEL || isEditing || isGeneratedImage) {
        setDisplayedText(safeText);
    }
  }, [safeText, msg.role, isEditing, smoothAnimation, isGeneratedImage]);

  useEffect(() => {
    if (isEditing) setEditText(safeText);
  }, [isEditing, safeText]);

  /**
   * 打字机动画循环
   * 根据缓冲区待处理字符数动态调整打字速度
   */
  useEffect(() => {
    if (!smoothAnimation || msg.role !== Role.MODEL || msg.isError || isEditing || isGeneratedImage) return;

    const animate = () => {
      setDisplayedText((current) => {
        const target = targetTextRef.current;
        if (current === target) return current;
        if (current.length > target.length) return target;

        const diff = target.length - current.length;

        /**
         * 动态调整打字步长：
         * 根据用户需求，提高比例为缓冲区字数 (diff) / 50。
         * 设置最小步长为 1，确保即使剩余字数较少也能匀速完成渲染。
         */
        const chunk = Math.max(1, Math.ceil(diff / 50));

        const nextLen = Math.min(target.length, current.length + chunk);
        const nextText = target.substring(0, nextLen);
        return nextText;
      });
      animationRef.current = requestAnimationFrame(animate);
    };

    animationRef.current = requestAnimationFrame(animate);
    return () => {
      if (animationRef.current) cancelAnimationFrame(animationRef.current);
    };
  }, [msg.role, msg.isError, isEditing, smoothAnimation, isGeneratedImage]);

  useLayoutEffect(() => {
      if (isLast && onScrollToBottom && smoothAnimation && msg.role === Role.MODEL && !isEditing && !isGeneratedImage) {
          onScrollToBottom();
      }
  }, [displayedText, isLast, onScrollToBottom, smoothAnimation, msg.role, isEditing, isGeneratedImage]);

  // --- 处理方法 ---

  const cancelEditing = () => { 
    setEditingId(null); 
    setEditText(''); 
    setConfirmDeleteId(null);
  };

  const saveEdit = () => { 
    if (editText.trim() !== safeText) onEditMessage(msg.id, editText); 
    setEditingId(null); 
    setConfirmDeleteId(null);
  };

  const handleKeyDown = (e: React.KeyboardEvent) => { 
    if (e.key === 'Enter' && !e.shiftKey) { 
      e.preventDefault(); 
      saveEdit(); 
    } 
    if (e.key === 'Escape') cancelEditing(); 
  };

  const handleDeleteClick = () => {
    setEditingId(null);
    if (isConfirmingDelete) {
      onDeleteMessage(msg.id);
      setConfirmDeleteId(null);
      if (deleteTimerRef.current) clearTimeout(deleteTimerRef.current);
    } else {
      setConfirmDeleteId(msg.id);
      if (deleteTimerRef.current) clearTimeout(deleteTimerRef.current);
      deleteTimerRef.current = setTimeout(() => {
        setConfirmDeleteId(null);
        deleteTimerRef.current = null;
      }, 3000);
    }
  };

  const handleRegenerateClick = () => {
    onRegenerate(msg.id);
    setConfirmDeleteId(null);
  }

  const handleImageClick = (src: string) => {
      if (onViewImage) {
          onViewImage(src);
      } else {
          window.open(src, '_blank');
      }
  };

  // --- 样式计算 ---

  const effectiveTransparency = isEditing ? 100 : bubbleTransparency;
  const borderAlpha = 0.5 + (effectiveTransparency / 100) * 0.5;
  const shadowAlpha = (100 - effectiveTransparency) / 100;

  const textShadowStyle = effectiveTransparency < 90 
    ? `0 1px 2px rgba(var(--color-theme-primary-rgb), ${shadowAlpha})` 
    : 'none';

  let backgroundColor;
  if (msg.role === Role.USER) {
       backgroundColor = `rgba(var(--color-theme-primary-rgb), ${effectiveTransparency / 100})`;
  } else if (msg.role === Role.MODEL && !msg.isError) {
       backgroundColor = `rgba(var(--color-theme-primary-rgb), ${(effectiveTransparency / 100) * 0.15})`;
  }

  const animationClass = smoothAnimation ? 'animate-pop-in' : '';
  const wrapperWidthClass = isEditing ? 'w-full max-w-full' : 'max-w-[95%] md:max-w-[85%]'; 
  const bubbleBorderColor = isVSCodeTheme ? 'transparent' : `rgba(var(--color-theme-primary-rgb), ${borderAlpha})`;

  const showAvatar = 
    avatarVisibility === 'always' || 
    (avatarVisibility === 'user-only' && msg.role === Role.USER) ||
    (avatarVisibility === 'model-only' && msg.role === Role.MODEL);

  return (
    <div className={`flex w-full ${containerClass} mx-auto ${msg.role === Role.USER ? 'justify-end' : 'justify-start'} animate-fade-in-up group`}>
        <div className={`flex gap-3 ${msg.role === Role.USER ? 'flex-row-reverse' : 'flex-row'} ${wrapperWidthClass}`}>

            {showAvatar && (
                <div className={`flex-shrink-0 w-8 h-8 rounded-full flex items-center justify-center mt-0.5 overflow-hidden ${msg.role === Role.USER ? 'bg-primary-600' : 'bg-transparent'} ${msg.isError ? 'bg-red-500' : ''}`}>
                    {msg.role === Role.USER ? <User className="w-5 h-5 text-white" /> : <div className="w-full h-full scale-150"><KirbyIcon theme={theme} isThemed={kirbyThemeColor} /></div>}
                </div>
            )}

            <div className={`flex flex-col min-w-0 ${msg.role === Role.USER ? 'items-end' : 'items-start'} w-full`}>
            <div 
                className={`relative px-3 py-2.5 rounded-2xl shadow-sm backdrop-blur-sm transition-all duration-300 w-full max-w-full origin-bottom-left ${animationClass} ${
                    msg.role === Role.USER 
                    ? 'text-white rounded-tr-sm border origin-bottom-right' 
                    : msg.isError 
                        ? 'bg-red-100 dark:bg-red-900/30 border border-red-200 dark:border-red-800 text-red-800 dark:text-red-200 rounded-tl-sm' 
                        : 'border text-gray-800 dark:text-gray-100 rounded-tl-sm'
                }`}
                style={
                    !msg.isError ? { 
                        backgroundColor,
                        borderColor: bubbleBorderColor,
                        textShadow: textShadowStyle
                    } : {}
                }
            >
                {/* 消息附件图片网格 */}
                {msg.images && msg.images.length > 0 && !isEditing && (
                    <div className="flex flex-wrap gap-2 mb-2">
                        {msg.images.map((img, idx) => (
                            <div key={idx} className="relative group">
                                <img 
                                    src={img} 
                                    alt="Message Attachment" 
                                    className="max-h-64 max-w-full rounded-lg cursor-pointer hover:opacity-90 transition-opacity" 
                                    onClick={() => handleImageClick(img)}
                                />
                            </div>
                        ))}
                    </div>
                )}

                {isEditing ? (
                <div className="w-full min-w-[200px]">
                    <AutoResizeTextarea 
                        value={editText} 
                        onChange={(e) => setEditText(e.target.value)} 
                        onKeyDown={handleKeyDown} 
                        fontSize={fontSize}
                        autoFocus
                        lang={language}
                    />
                    <div className="flex justify-end gap-2 mt-2">
                        <button 
                        onClick={cancelEditing} 
                        className={`p-2 rounded-lg transition-colors flex items-center justify-center ${
                            msg.role === Role.USER 
                                ? 'bg-white/20 text-white hover:bg-white/30' 
                                : 'bg-primary-600 text-white hover:bg-primary-700 shadow-sm'
                        }`} 
                        title={t('action.cancel', language)}
                        aria-label={t('action.cancel_edit', language)}
                    >
                            <X className="w-5 h-5 md:w-4 md:h-4"/>
                        </button>
                        <button 
                        onClick={saveEdit} 
                        className={`p-2 rounded-lg transition-colors flex items-center justify-center ${
                            msg.role === Role.USER 
                                ? 'bg-white/20 text-white hover:bg-white/30' 
                                : 'bg-primary-600 text-white hover:bg-primary-700 shadow-sm'
                        }`} 
                        title={t('action.confirm', language)}
                        aria-label={t('action.save_edit', language)}
                    >
                            <Save className="w-5 h-5 md:w-4 md:h-4"/>
                        </button>
                    </div>
                </div>
                ) : (
                    <MessageContent 
                        content={displayedText}
                        role={msg.role}
                        isError={msg.isError}
                        images={msg.images}
                        textWrapping={textWrapping}
                        fontSize={fontSize}
                        language={language}
                        theme={theme}
                        onShowToast={onShowToast}
                        onViewImage={onViewImage}
                        isLast={isLast} // Pass isLast to control auto-expansion of thoughts
                        groundingMetadata={msg.groundingMetadata}
                    />
                )}
            </div>

            <div className="flex flex-wrap items-center gap-x-2 gap-y-1 mt-1 px-1 min-h-[1.5rem]">
                <span className="text-[10px] text-gray-400 dark:text-gray-500 whitespace-nowrap">{new Date(msg.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</span>
                {msg.role === Role.MODEL && !msg.isError && (
                <div className="flex flex-wrap items-center gap-1">
                    {msg.keyIndex && (
                        <span className="text-[10px] font-mono bg-primary-50 dark:bg-primary-900/20 text-primary-600 dark:text-primary-400 px-1 rounded border border-primary-100 dark:border-primary-800 whitespace-nowrap" title={t('tooltip.key_index', language)}>#{msg.keyIndex}</span>
                    )}
                    {showGroupName && msg.groupName && (
                        <div className="flex items-center gap-0.5 text-[10px] font-mono bg-primary-50 dark:bg-primary-900/20 text-primary-600 dark:text-primary-400 px-1 rounded border border-primary-100 dark:border-primary-800 whitespace-nowrap" title={t('tooltip.group_name', language)}>
                            <Folder className="w-2.5 h-2.5" />
                            <span>{msg.groupName}</span>
                        </div>
                    )}
                    {showModelName && msg.model && (
                        <span className="text-[10px] font-mono bg-primary-50 dark:bg-primary-900/20 text-primary-600 dark:text-primary-400 px-1 rounded border border-primary-100 dark:border-primary-800 break-all max-w-[250px]" title={t('tooltip.model_used', language)}>{msg.model}</span>
                    )}
                    {showResponseTimer && msg.executionTime && (
                        <div className="flex items-center gap-0.5 text-[10px] font-mono bg-primary-50 dark:bg-primary-900/20 text-primary-600 dark:text-primary-400 px-1 rounded border border-primary-100 dark:border-primary-800 whitespace-nowrap" title={t('tooltip.response_time', language)}>
                            <Clock className="w-2.5 h-2.5" />
                            <span>{t('label.response_time', language).replace('{duration}', (msg.executionTime / 1000).toFixed(1))}</span>
                        </div>
                    )}
                </div>
                )}
                {!isLoading && !isEditing && (
                <div className={`flex items-center gap-2 opacity-0 group-hover:opacity-100 transition-opacity`}>
                    <button 
                    onClick={() => startEditing(msg)} 
                    className="p-4 md:p-1 text-gray-400 hover:text-primary-600 dark:hover:text-primary-400 transition-colors"
                    title={t('action.edit', language)}
                    aria-label={t('action.edit_message', language)}
                    >
                    <Edit2 className="w-3.5 h-3.5" />
                    </button>
                    <button 
                    onClick={handleRegenerateClick} 
                    className="p-4 md:p-1 text-gray-400 hover:text-primary-600 dark:hover:text-primary-400 transition-colors"
                    title={msg.role === Role.USER ? t('action.regenerate_from_user_message', language) : t('action.regenerate_response', language)}
                    aria-label={t('action.regenerate', language)}
                    >
                    <RefreshCw className="w-3.5 h-3.5" />
                    </button>
                    <button 
                    onClick={handleDeleteClick} 
                    className={`p-4 md:p-1 transition-colors ${isConfirmingDelete ? 'text-red-500 bg-red-50 dark:bg-red-900/20 rounded' : 'text-gray-400 hover:text-red-500'}`}
                    title={isConfirmingDelete ? t('action.confirm_delete', language) : t('action.delete', language)}
                    aria-label={t('action.delete_message', language)}
                    >
                    <Trash2 className="w-3.5 h-3.5" />
                    </button>
                </div>
                )}
            </div>
            </div>
        </div>
    </div>
  );
}, (prev, next) => {
  return (
    prev.msg === next.msg &&
    prev.isEditing === next.isEditing &&
    prev.isConfirmingDelete === next.isConfirmingDelete &&
    prev.isLoading === next.isLoading &&
    prev.bubbleTransparency === next.bubbleTransparency &&
    prev.textWrapping === next.textWrapping &&
    prev.fontSize === next.fontSize &&
    prev.showModelName === next.showModelName &&
    prev.showGroupName === next.showGroupName &&
    prev.showResponseTimer === next.showResponseTimer &&
    prev.language === next.language &&
    prev.theme === next.theme &&
    prev.kirbyThemeColor === next.kirbyThemeColor &&
    prev.smoothAnimation === next.smoothAnimation &&
    prev.isLast === next.isLast &&
    prev.avatarVisibility === next.avatarVisibility
  );
});

